INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '带母亲复查身体，离中肿很近。环境很好，服务很好，很干净。下次有机会还会再来这里居', '带母亲复查身体，离中肿很近。环境很好，服务很好，很干净。下次有机会还会再来这里居住。', '2023-08-29', 5, '[''整体满意度'', ''卫生状况'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0236e12000c12q988F81D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '超级喜欢花园酒店的建筑风格，房间和酒店位置不错，一层的花园也很美，颇显老牌白金五', '超级喜欢花园酒店的建筑风格，房间和酒店位置不错，一层的花园也很美，颇显老牌白金五星级酒店的底蕴。不过床品过软，两晚都没睡好，早餐一般，需要提升。', '2023-07-09', 5, '[''房间设施'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232q12000bm7kkq5E082_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233612000bm7pea0521D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233x12000bm7j344373E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233i12000bm7qjvqF0E0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233s12000bm7k6cl5950_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230c12000bm7qvg55AFB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '去广州玩还是想体验一下广式传统酒店，就定在了花园，服务态度一级棒，瀑布餐厅早餐很', '去广州玩还是想体验一下广式传统酒店，就定在了花园，服务态度一级棒，瀑布餐厅早餐很好吃，酒店门口就是地铁站??，方便出行，谢谢viria', '2023-07-16', 5, '[''交通便利性'', ''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235s12000bo23o088E09_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232p12000bo25uw99FE0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间很新，床很舒服，环境优美，非常棒的一次体验。', '房间很新，床很舒服，环境优美，非常棒的一次体验。', '2023-10-01', 5, '[''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235b12000capm3izE195_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230n12000capjth6744F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230b12000caprnb28913_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '行政酒廊的yuki外国小姐姐特别热情 很可爱', '行政酒廊的yuki外国小姐姐特别热情 很可爱', '2023-10-04', 4, '[''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234s12000cbujx04D007_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '每次到广州都住这里，老牌五星酒店。服务贴心。交通方便。每一次帮我免费升级，房间卫', '每次到广州都住这里，老牌五星酒店。服务贴心。交通方便。每一次帮我免费升级，房间卫生条件很好，总之都很满意！', '2023-08-05', 5, '[''整体满意度'', ''交通便利性'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0233812000bu2mpp8472C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233d12000bu2mlly4D23_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231f12000bu2rzvmF4AC_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '位置：酒店位于靠近地铁口，周边有商场，位置优越', '位置：酒店位于靠近地铁口，周边有商场，位置优越
服务：一进酒店就有热情的小姐姐接待，送了我们中秋花灯，还介绍周边和酒店游玩的地方
环境：酒店大堂富丽堂皇，正中间是一整面金箔雕刻而成的红楼梦大观园，旁边还有旋转楼梯，很适合打卡拍照。当然最吸人眼球的就数一口的瀑布餐厅，18米双瀑布搭配透明落地窗，分分钟都是大票
房间：这次给我升级了行政套房，有会客区和卧室，喜欢双洗漱台的设计，再也不用和姐妹抢洗漱台啦
需要特别推荐下四楼的博物馆，这里记录了花园酒店的历史，还有世界各地的特色酒店，值得一逛。', '2023-10-07', 5, '[''周边配套'', ''前台服务'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232012000cck6wjq1049_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232112000cckbc6z6E15_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234512000ccka14g1B03_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231y12000cckaf7x91F5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232u12000cckaf7zD092_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231g12000cckccen461D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境：一流，无论是本土还是外籍工作人员都很nice', '环境：一流，无论是本土还是外籍工作人员都很nice
服务：五星好评
设施：有博物馆餐馆，后花园很舒服，餐厅也不错。
下次再来', '2023-07-16', 5, '[''整体满意度'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230k12000bo71znlEABE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231512000bo71oqc8F15_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230f12000bo6vcs164DC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230q12000bo6wap5B773_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232u12000bo70pkyA8AB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231l12000bo6zz9j334D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230a12000bo6vy7gCBC7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店非常有特色，味道也很好闻，宝格丽的洗护用品，4楼还有酒店博物馆，周边吃的也很', '酒店非常有特色，味道也很好闻，宝格丽的洗护用品，4楼还有酒店博物馆，周边吃的也很多，户外泳池也很干净，适合商务，亲子游，前台的Doris也很nice，态度很好', '2023-06-20', 5, '[''公共设施'', ''周边配套'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231712000bgj7l7dA116_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230512000bgjeu80ABA3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231e12000bgja1hr51CD_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '早在携程上买的套餐圈，有幸来此体验一下白金五星级酒店的感受，太值了，酒店装饰处处', '早在携程上买的套餐圈，有幸来此体验一下白金五星级酒店的感受，太值了，酒店装饰处处显示着奢华高端，中西合璧，好养眼哦！服务更是一流，进店就有迎宾小姐引路，虽然前台非常忙碌，还很耐心细致，前台的美女小梁为了我们的套餐落实，几经周折才完事，在此特别感谢！', '2023-12-08', 5, '[''性价比'', ''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232412000cp32cxp3E45_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230r12000cp30nl695CC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230q12000cp38kghF5D8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236r12000cp378ko2984_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.co