', '2023-04-30', 1, '[''卫生状况'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233812000b4afuyq1991_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231r12000b4agrwi0FC5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236t12000b49z1hs0CB1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234012000b4adrmn7EF6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '位置：酒店位于市中区，地铁5号线淘金站A出口出来右手边就是，非常方便。旁边有荔湾', '位置：酒店位于市中区，地铁5号线淘金站A出口出来右手边就是，非常方便。旁边有荔湾肠粉、陶陶居、常来小聚餐馆、赵记传承糖水铺。酒店对面是友谊商场，里面有广州酒家。
