itle, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境：有文化底蕴', '环境：有文化底蕴
服务：很热情
瀑布餐厅的早餐样式丰富', '2023-08-02', 5, '[''餐饮设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234e12000bt1z5mqA2D9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235d12000bt1qhw88B60_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233x12000bt1phm6A8CD_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '白金五星酒店果然居住体验比较棒，可以免费加床送了小羊羊和自助餐，后花园也特别漂亮', '白金五星酒店果然居住体验比较棒，可以免费加床送了小羊羊和自助餐，后花园也特别漂亮瀑布壮观，服务人员态度非常好，尤其是表扬Gillian，服务周到。', '2023-12-31', 5, '[''整体满意度'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235e12000cu6tplj2509_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233d12000cu6tjo90AC1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235r12000cu6vpr3029B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231b12000cu6qux59AE6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230212000cu6tar5EFEC_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州有好几家充满历史感的酒店，白天鹅，白云宾馆，广州花园酒店等，之前来广州一直都', '广州有好几家充满历史感的酒店，白天鹅，白云宾馆，广州花园酒店等，之前来广州一直都是住的希尔顿，万豪这种国际酒店集团，这次想体验一下本土酒店，感受一下不同酒店不同的风格，没想到这是一切灾难的开始，除了携程赠送的600元餐券感觉物有所值，客房，服务都不行，连换二家房都能有问题，看来这家曾经荣誉满满的酒店如今也是今非昔比，真心建议最近要来广州的，他们家只适合拍照吃饭，千万不要住进来。
先说优点，酒店地理位置得天独厚，距离广州站很近，旁边就是地铁站，出行游玩很方便。大堂看起来很气派，办理入住要排队，生意很好。酒店自带9家餐厅，日料，西餐，粤菜，下午茶，各种品种俱全，我居然还在其中发现了泰安门的身影，厉害了。健身房很大，设施齐全，圆形拱门设计有种欧式古堡风，户外无比泳池拍照也挺好看的，还自带一个博物馆供住客参观，单看以上公共区域设备，的确看起来是一家五星酒店了。
房间真的不怎么行，第一家房一进去就有一股难闻的尿骚味，马桶不是智能的，用完以后一直滴水声不断，让酒店派人上门查看，在房间洗完衣服休息好整整1小时没人上门。于是自己下楼和酒店员工说了情况，一个男性员工表示会立即派人上门查看，于是我就放心出门去了。等玩了一圈回来，房间情况依旧未改善，还是如此，无奈再次联系酒店，这时出来一个戴眼镜的女人，貌似是酒店楼层经理，全程没有笑容没有一句抱歉全程黑脸回应，大意就是他们维修部门上门检修时候说马桶没有声音，于是就走了，我让她自己站在马桶这里听，这下她赖不掉了，因为声音真的是有，而且持续不断。于是她黑着脸说那就给你换一个房间，好像是我故意刁难酒店一样。接着还有更离谱的话呢，“你现在不要出门，在房间等电话，酒店生意太好，不知道什么时候房间收拾出来，到时候你接到电话再换新房间。”What？我差点以为我耳朵坏了，我花钱是来旅游的，你让我呆在这个滴水房间里听噪音不要出门，还不告诉具体要等多久，我要听你话我大概真的是发傻哦。这个女人说完话头也不回就走了，我等她走了也去博物馆了，我早就安排好的行程也不可能因为她莫名其妙取消。再加上这个酒店所有前台无论何时路过都是大排长龙，我要找人投诉估计也是要浪费我很久时间，还是先出门再说。
等到晚上17:30回到酒店，先去餐厅把券用完吃了一个晚餐，然后我自己拿着房卡去前台要求换房间，服务员帮我换了一个比原先21楼低的18楼房间，房型没有升级，等于是自动降级了，我早就对这个酒店彻底失望，反正以后不会再来，只求房间没味道没异响即可，接着戏剧性的一幕来了，晚上21:30左右，酒店整个18楼跳闸，坐在房间就像**，灯光自动忽闪忽灭，庆幸自己当时自己没洗澡，要不然黑灯瞎话摔在浴室不知道找谁算账呢。
平心而论，花园酒店公区设计，中餐厅水准和餐厅服务员都很优秀，就是房间实在老旧问题不断个人感觉应该停业维修保养了，再加上那个可恶的戴眼镜客房经理讲话素质奇差无比，看这样子就知道这个酒店管理有多混乱，管理人员素质都参差不齐了。
整体来说广州五星酒店比起香港，深圳来说服务真的要差了一大截，这家花园酒店是住过最差的，真想打负分，一星都嫌多。', '2023-02-14', 1, '[''房间设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0206d12000ao2r2cr49E4_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0234a12000ao2hjh2A2EC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236q12000ao2i7a15A75_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231c12000ao2nnfl6C8D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236s12000ao2njq6311B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231m12000ao2l4nz4396_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235f12000ao2p13hA506_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231g12000ao2kqynABEF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232b12000ao2kzii492D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230u12000ao2jsdu3240_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '足足十年没有去过花园酒店了，这次去没有失望，感慨良多，酒店整体装饰保留着原来的风', '足足十年没有去过花园酒店了，这次去没有失望，感慨良多，酒店整体装饰保留着原来的风格，也增加了一些新的元素，比如前台变成了一个个独立办理入住的柜台，很多改变都很好，房间也翻新过，前台Semmy 的服务非常好，包括餐厅和大堂吧的服务都很好。我自己做酒店行业，说实话，花园酒店的配套是广州酒店行业里面，我认为没有其他酒店能超越。另外能保持这么好的服务水平，真的超出我的期望。', '2023-04-05', 5, '[''整体满意度'', ''前台服务'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232g12000auy2tyj7A31_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233n12000auxt1h9B6B5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '十颗星的入住体验！给前台betty好评！非常满意！', '十颗星的入住体验！给前台betty好评！非常满意！', '2023-08-27', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235z12000c0imzigF1D3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236s12000c0inun76967_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234212000c0irji531B4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231812000c0ir4oo7EA5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234c12000c0inj5u19EE_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '来了很多次了 一如既往地喜欢 吃喝玩乐都在酒店里了 三楼参观了广州花园自己的博物', '来了很多次了 一如既往地喜欢 吃喝玩乐都在酒店里了 三楼参观了广州花园自己的博物馆，吃了一楼日料，二楼的正宗广式小吃，都是大众点评上不错的餐厅。

