egory, images) VALUES ('未知酒店', '未知地点', '匿名', '我们这次入住五晚，对花园酒店的环境服务设施非常满意。 美丽的后花园，优雅的桃园馆', '我们这次入住五晚，对花园酒店的环境服务设施非常满意。 美丽的后花园，优雅的桃园馆和田园浪漫的荔湾亭，丰富多彩的博物馆，房间内的设置也是很贴心。酒店一流的服务人员素质高，很赞。感谢酒店人员的热情接待。', '2023-03-04', 5, '[''整体满意度'', ''公共设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234812000aqigtexC673_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232d12000aqigp4n1421_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232912000aqijgohF5D7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232912000aqipawyA93F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232g12000aqiiwd001BF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233012000aqikayqAAB0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234h12000aqiifh19A35_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235812000aqifox3A928_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233i12000aqihtqzFD0F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店有后花园、瀑布很美，大堂气派，门口服务生会主动帮拿行李，酒店历史导览介绍', '花园酒店有后花园、瀑布很美，大堂气派，门口服务生会主动帮拿行李，酒店历史导览介绍非常好，一楼西式早餐正常。客房设施、家具特别陈旧，有些功能已坏，墙角发霉墙纸发黄，家具破败，完全不像2019年装修，住的无烟楼层二个晚上房间有烟味，跟酒店反映给了一个空气净化器，说对客人在房间内偷偷吸烟酒店也没办法。', '2023-03-03', 3, '[''房间设施'', ''卫生状况'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232412000aqfjfu1C8D5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236212000aqfhwdz4097_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231012000aqfk6za228D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常不好的一次商务住宿、酒店房间30平米没有窗户一晚要1200元、洗澡站在浴缸里', '非常不好的一次商务住宿、酒店房间30平米没有窗户一晚要1200元、洗澡站在浴缸里跟厕所共用一个铁门很沉重不方便推来推去。桌子上的插座没电。家具貌似二手市场买来的、前台服务人员衣冠不整头发凌乱、说话也不耐烦。不小心定了个双床房要求更改说大床房要下午五点后才能入住、那就双床房吧要求第二天两点以前退房结果说只能一点钟退房。下次不会再住这个老牌五星级酒店', '2023-02-25', 1, '[''房间设施'', ''前台服务'', ''价格合理性'']', '["[ \"https://dimg04.c-ctrip.com/images/0232v12000apmkidz73A1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234n12000apmy6n5F55D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235612000apn03071945_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230c12000apmu7i46F20_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '已经很久没有遇到各个方面都没有雷点的酒店了。入住了粤韵客房（金卡升级的），房间很', '已经很久没有遇到各个方面都没有雷点的酒店了。入住了粤韵客房（金卡升级的），房间很新很舒服。

服务：从前台到礼宾到客房还有餐厅都体验很好，虽然酒店有高达约850间的客房，但是依旧一切都井然有序，对于定位豪华或者奢华的五星级酒店来说并不是简单的事情。

设施：红棉客房往上就蛮大面积了，很舒服。酒店的几家餐厅轮着吃一吃就很舒服了，满意。

吃完还可以去花园里看看锦鲤。', '2023-02-04', 5, '[''整体满意度'', ''房间设施'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236l12000al8bsfd11EE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235812000al7n0q7405D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231r12000al8krsy5F99_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234j12000al88gxkCB30_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234p12000al7ilwg9C88_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236g12000al87zg46227_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232712000al7q3qe44B6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233712000al8lxokD4DC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234p12000al8hfr75CA0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '还不错，酒店服务很好。下次还会入住，希望保持', '还不错，酒店服务很好。下次还会入住，希望保持
服务：很好
环境：周边在装修
卫生：很细致
设施：老旧。房间重新装修了，但是房间比较小呢', '2023-06-15', 5, '[''整体满意度'', ''客房服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0235a12000bf0zr8p619A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234212000bf11b3mFB95_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230g12000bf0vx0d4C3B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店位置好，交通方便，吃方便，周边点德都，陶陶居，广州酒家等，都很近。大堂高大尚', '酒店位置好，交通方便，吃方便，周边点德都，陶陶居，广州酒家等，都很近。大堂高大尚，有五星级酒店的派头，客房嘛，毕竟是老酒店了！
服务挺好的！
入住时，花园饭店的商会在搞活动。', '2023-03-12', 4, '[''交通便利性'', ''周边配套'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232s12000arj0wha62BB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235p12000arj26t26232_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233512000arj8dbc004E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常棒的一次体验，入住酒店还送了点心和水果?早餐在酒店的旋转餐厅，小孩子很喜欢?', '非常棒的一次体验，入住酒店还送了点心和水果?早餐在酒店的旋转餐厅，小孩子很喜欢??前台的小姐姐（Savanna小圆）服务很专业贴心，虽然国庆期间入住等待时间长，但是等待入住的时间有乐队表演，还给小孩送了小点心和花花，非常棒的一次体验?推荐??', '2023-10-05', 5, '[''前台服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232t12000cc21mvoFA68_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232412000cc20ve87DB5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231z12000cc1xqhq58FD_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店前台接待态度很好??，能满足客人的需求，酒店的后花园非常nice,房间卫生干', '酒店前台接待态度很好??，能满足客人的需求，酒店的后花园非常nice,房间卫生干净整洁，床品也非常舒服，酒店有各种美食，能满足各地客人的需求，口感非常好，这是一次非常棒的入住体验，非常满意????', '2023-03-05', 5, '[''前台服务'', ''卫生状况'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231e12000aqlvqdi4A37_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230s12000aqm8l043230_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间很nice 前台Billy也很热情 专业 好评 ', '房间很nice 前台Billy也很热情 专业 好评 
下次还会再来的 还有很哇塞的瀑布餐厅', '2023-09-09', 5, '[''前台服务'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/023112224wdqwjso11E61_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231w2234ch42mz9c2131_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/023142215gadqhonk75E3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '设施：就在地铁边上，交通很方便，停车免费，还可以充电呢。床超级舒服，睡了一个大懒', '设施：就在地铁边上，交通很方便，停车免费，还可以充电呢。床超级舒服，睡了一个大懒觉。
卫生：完全符合白金五星的要求，安心使用。
服务：必须为前台的Elvis，Mikey点赞，他们的用心服务让我以后都必须选择花园，真让我开心满意。', '2023-03-13', 5, '[''交通便利性'', ''房间设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231d12000arok098FCAE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235u12000arodshj38B3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232i12000arogaj682B9_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店位置很好，门口就是5号线淘金站，3、8、4号都很方便，酒店不愧是老牌五星酒店', '酒店位置很好，门口就是5号线淘金站，3、8、4号都很方便，酒店不愧是老牌五星酒店，各方面都很不错，房间略小，主要洗漱和卫生间空间比较局促。最令我们印象深刻的是客服服务小李，因为前一天大热天去了长隆，喝了很多水，房间里留了好几个矿泉水空瓶，他不但多给我们补了两瓶水，还手写了一张便条给我们，让人感觉太贴心了。', '2024-08-10', 4, '[''交通便利性'', ''客房服务'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230c12000f2mzwpa8E45_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236m12000f2mv48t7021_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务热情，特别是前台viria的服务让我们有宾至如归的感觉。地理位置好，门口就是', '服务热情，特别是前台viria的服务让我们有宾至如归的感觉。地理位置好，门口就是地铁口，出行方便。酒店景观美，下次还会选择入住', '2024-05-27', 5, '[''前台服务'', ''交通便利性'', ''景观/朝向'']', '["[ \"https://dimg04.c-ctrip.com/images/0235u12000e6sm9c990BC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233u12000e6ssen7412C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232012000e6smql41AC1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234f12000e6snx2249DF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230412000e6ssgumFD37_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235a12000e6susi0FE19_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次出行前做了好久的选择最后选择了？花园酒店，因为想让妈妈和孩子体验岭南文化，在', '这次出行前做了好久的选择最后选择了？花园酒店，因为想让妈妈和孩子体验岭南文化，在入住前看到一些不好的评价心里也有点忐忑，可当我们从进入酒店开始就感受到各种温馨。前台看到我带着两个娃给我升级了新翻新的套房，办理入住后还有专人帮忙带上房间，入住了两天酒店的卫生和服务都非常到位，可以用一句成语宾至如归概括，六月份去广州一定会再次预定花园酒店，真心推荐！
设施：新装修的房间，设施齐全，卫生间的防臭做得非常完美！
卫生：干净整洁
环境：舒适
服务：yyds', '2023-03-06', 5, '[''整体满意度'', ''前台服务'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235k12000aqriydu0FD9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235b12000aqriiwk1ABD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236912000aqriwv4D537_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235o12000aqrijzg7A26_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235f12000aqrikla1443_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230k12000aqrh0es828A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231n12000aqrj73u7962_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233612000aqrod0t4797_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231812000aqriq22FFC4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老酒店了，值得体验', '老酒店了，值得体验', '2023-09-11', 4, '[''整体满意度'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0234e12000c3z8lmiA59A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '闹市区地铁口，环境非常好隔音很棒，有私家小花园，瀑布水榭亭台楼阁健身房，游泳池，', '闹市区地铁口，环境非常好隔音很棒，有私家小花园，瀑布水榭亭台楼阁健身房，游泳池，中西餐厅各取所需！同时传播岭南文化，房间布置很有特色', '2023-04-07', 5, '[''公共设施'', ''安静程度'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0231412000avoowcs4D70_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230612000avouvfb619B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232q12000avod0ss9439_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230412000avop5sj9EA2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州人的情怀，老牌五星酒店但依然焕发着粤韵活力', '广州人的情怀，老牌五星酒店但依然焕发着粤韵活力', '2023-06-25', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234h12000bhs68pmD1DF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', 'kristy服务很好，酒店环境很好', 'kristy服务很好，酒店环境很好', '2023-07-08', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230k12000blqz15dD5E2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '总体来说，花园酒店的设施和服务都挺好的，床品都很舒服。不过，我们订的时候有送博物', '总体来说，花园酒店的设施和服务都挺好的，床品都很舒服。不过，我们订的时候有送博物馆的票，但是在办入住的时候，前台忘记给我们了，直到check out时候才给，大家自己记得要吧，没有限期，下次再用吧', '2023-02-19', 5, '[''前台服务'', ''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233m12000aovqpr9617B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '推荐给长隆玩过之后，想留一天的时间给老广州感受岭南文化的朋友。', '推荐给长隆玩过之后，想留一天的时间给老广州感受岭南文化的朋友。

        酒店在繁华的淘金区，长隆玩过之后打车40分钟左右就到酒店了。因为酒店开业时间早，期望并不高。一进入酒店大堂，我们一家三口就感慨这是此行最满意的酒店了。

         携程白金卡会员订房后可以自动成为岭客汇金卡享受行政酒廊待遇。特别值得体验的是行政酒廊的早餐。推荐户外位置用餐，在瀑布和花园旁享用自助+单点美食，轻松拥有度假的松弛感。不用担心户外位置叫不到服务人员的情况，carrie，Danil, lisa几位工作人员会随时check用餐情况。家有嗦粉爱好者的朋友们，推荐尝试一下米粉+牛腩+云吞的组合，家中乐宝整碗汤全部喝完。', '2023-02-13', 5, '[''餐饮设施'', ''整体满意度'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0235b12000anz7lw4CC49_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235w12000anz6p865710_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233812000anza9xlB01A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236i12000anz6bgjDD31_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234s12000anyzu8u36E0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235712000anz0epbBBAB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店设施齐全，房间也很干净整洁，保洁大姐很热情，每次见面都会问有什么需要；前台小', '酒店设施齐全，房间也很干净整洁，保洁大姐很热情，每次见面都会问有什么需要；前台小姐姐办理入住，讲解很细致；酒店里有自己的花园，风景很好，每天都会带孩子去院子里转转；早餐也特别咱，种类丰富。值得推荐', '2023-03-06', 5, '[''整体满意度'', ''房间设施'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0231s12000aqr7bc00C0C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234912000aqr6glc93A7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230c12000aqr4ndi2F2F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '集文化，美食，园林景观于一体的酒店。酒店内有博物馆和多家餐厅。日料，味道很不错。', '集文化，美食，园林景观于一体的酒店。酒店内有博物馆和多家餐厅。日料，味道很不错。早餐，下午茶和欢乐时光都在锦里吧用餐。菜品非常棒，服务也周到。特别是锦里吧的印度籍女生Carre更是贴心。非常棒的体验。', '2023-06-26', 5, '[''餐饮设施'', ''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236j12000bi4g7dpF697_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230a12000bi4mdbpDE2C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234k12000bi48g7j449A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230e12000bi4fi08C5C1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230d12000bi4jmkp60CB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235812000bi49uqjF0FB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231c12000bi4jxv23D82_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235112000bi4jpt2ED47_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234812000bi48mplC746_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常有历史文化感的一个老牌国宾馆似的酒店。首先地理位置真的对于刚来广州的朋友很友', '非常有历史文化感的一个老牌国宾馆似的酒店。首先地理位置真的对于刚来广州的朋友很友好，出门就是地铁淘金站，周围吃饭 打车 都很方便。
老牌酒店的管理和服务接待都做的很好，一进门就有礼宾司的先生帮我们推行李，排队中也有接待人员引导，跟办理入住时候的小姐姐更是亲切惬意的对话，如沐春风。
房间帮我们升级到套房，虽然有些古旧，毕竟老酒店了，但是总的来说性价比超级高了。没有过分超出付出的要求来讲我觉得下次来广州我还会入住。
大堂富丽堂皇中有浓浓岭南风情，主要米其林餐厅好几个都在此酒店，早早预定的我们简直每天下楼就是幸福的感觉～', '2023-02-18', 5, '[''交通便利性'', ''前台服务'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0230712000aorymu402D7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237312000aorzb5fF050_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234r12000aoruz0wC355_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230f12000aos66488DE9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232t12000aoryzmzB292_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236j12000aos6atk090D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231w12000aos5uxqD621_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231612000aos12y26CC3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '入住广州花园酒店，整体体验非常不错。', '入住广州花园酒店，整体体验非常不错。
酒店的环境优雅，房间宽敞明亮，地理位置位于广州的老中心，环市路核心地段，新装修后的红棉套房现代而不失温馨。房间内的设施齐全，床铺舒适，完全能让人在一天的奔波后能拥有一个安静、舒适的休息空间。
酒店的餐饮选择也很丰富，早餐种类多样，满足了不同客人的口味需求。总的来说，装修后的广州花园酒店绝对是一家值得信赖的酒店，无论是商务出行还是休闲旅游，都能让客人享受到高品质的服务和舒适的住宿环境。特别感谢前台的Betty，工作效率高，态度和蔼可亲，脸上总是洋溢着温暖的笑容。即使在忙碌的时候，她也能迅速办理入住和退房手续，让客人感受到酒店的专业服务。', '2025-03-24', 5, '[''整体满意度'', ''前台服务'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232u12000ja2lwwcF42E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234712000ja29yuf81AD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231g12000ja4682b2260_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231r12000ja34qhg203F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232u12000ja3tsz315BD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235712000ja2ii2i2787_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233b12000ja3r7h345F6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234312000ja4depb29FC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236t12000ja4es198251_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '第一次去广州玩选到这个酒店真的很不错，酒店的风景很美池塘里有很多鲤鱼很好看，还有', '第一次去广州玩选到这个酒店真的很不错，酒店的风景很美池塘里有很多鲤鱼很好看，还有一个很有特色的瀑布餐厅，早上起来看着瀑布吃着早餐很不错，而且交通也很方便去哪都很近，酒店拍照也很美，房间也住的很舒服，住的那个房间可以看见瀑布和一半的广州塔非常好', '2023-02-13', 5, '[''景观/朝向'', ''餐饮设施'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0202q12000anz4wk5BAE5_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0233i12000anyyh40C4C9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231f12000anyy5saBE35_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235k12000anyzghrF409_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234h12000anys464B8A7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236r12000anywbb702E9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236o12000anyzmyfC207_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '每次来广州都想住这家酒店，这次终于订到房间了，过年的原因，办理入住的宾客很多，酒', '每次来广州都想住这家酒店，这次终于订到房间了，过年的原因，办理入住的宾客很多，酒店的服务很细心，还给等待的宾客送了饮料鲜花，整个大堂布置很有年味，后面的花园环境很优美，闹中取静。房间给人感觉有点压抑，走廊和房间的内空都比较矮，入住时安排的房间在五楼，窗户不能打开，而且外面就是平台，窗外没什么景观，而且沙发上还残留长头发，给人第一感觉不是很好，协调前台马上给换了六楼的一间，稍好一点，面盆的龙头是松的，晃晃悠悠，维修部及时修复，洗澡的细节不是很好，每次淋浴都要跨进浴缸，老年人可千万要当心不要摔倒。值得肯定的是酒店服务很到位很热情很专业！', '2023-01-27', 4, '[''前台服务'', ''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0203512000ailm00s44E7_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0236n12000aili6bu6685_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234n12000ailj5dkE494_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231012000ailjq7sA7D5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233c12000ailj9ce5774_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234h12000aili33dED3C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233l12000ailii3x4029_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232w12000ailihvwCD21_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230n12000ailixuy9A25_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231c12000ailitkl6EA3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店卫生干净整洁，环境优雅！舒适！地理位置很好，设施齐全！', '酒店卫生干净整洁，环境优雅！舒适！地理位置很好，设施齐全！', '2023-06-06', 5, '[''卫生状况'', ''整体满意度'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0236b12000bd5k2eaE332_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234j12000bd5fp17250C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235j12000bd5dv6yF1D8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235f12000bd5ehsuD94C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237412000bd57n2c00E2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '宝藏酒店！入住升级了房型 房间非常大！瀑布餐厅的环境非常好，还有免费的博物馆可以', '宝藏酒店！入住升级了房型 房间非常大！瀑布餐厅的环境非常好，还有免费的博物馆可以逛！周围也有很多商场 店铺 地铁就在旁边 非常方便', '2023-04-04', 5, '[''交通便利性'', ''周边配套'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230x12000aulk2me5A4B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232r12000aulq1oh88D5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '反正就是很不值', '反正就是很不值
设施大概80年代的
到处有霉点，有物资
客服不积极
前台接待服务很差
明明提前联系好，确认好房型
结果还是弄错了房型，和订的不一样！
前台说没房间了，不能给我订的，what？这是我的错么？？？
门厅很好看，大气
房间就呵呵了', '2023-03-11', 1, '[''前台服务'', ''房间设施'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0234712000arggzmw72F6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231k12000anrm7i578FC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236v12000anrm7i31427_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '总体而言，我的广州花园酒店之行是一次非常满意的体验。酒店的优雅环境、舒适的客房、', '总体而言，我的广州花园酒店之行是一次非常满意的体验。酒店的优雅环境、舒适的客房、美味的餐饮以及前台Nicky等员工的优质服务，都让我的住宿体验变得难忘。我强烈推荐广州花园酒店给那些寻求高品质服务和舒适住宿的旅客。', '2024-12-22', 5, '[''整体满意度'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231l12000hch7hukB7F6_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0231512000hch7zltB182_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0230g12000hch82xf359B_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店的位置非常优越，门口就有地铁，出行便利，酒店的餐厅环境优美，用餐时使人心情愉', '酒店的位置非常优越，门口就有地铁，出行便利，酒店的餐厅环境优美，用餐时使人心情愉悦，服务人员也很负责到位。酒店房间设施一般，洗澡只能站在浴缸里，没有喷淋的独立空间，对于老人和儿童很不友好！没有数据线插孔，这个就很不方便，不足之处希望加以改变！', '2023-02-11', 4, '[''房间设施'', ''交通便利性'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234d12000anbrc1f4BAD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236a12000anbvtou6689_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234j12000anb63cd6E78_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231112000anbfhoh8586_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233e12000anb6keyAE52_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230c12000anb1kn196B7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '前台服务态度好，热情，g开头英文名字服务人员，很快帮我们办理了入住，还免费升级房', '前台服务态度好，热情，g开头英文名字服务人员，很快帮我们办理了入住，还免费升级房间，赞！酒店环境不错，推荐来广州首选入住。', '2024-05-11', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233812000dyhc7yj66F8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235g12000dyha6se6047_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232a12000dyh6qrz6526_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店服务很好，下车就有人帮拿行李，大堂大气，办理入住井然有序，我非周末节假日去的', '酒店服务很好，下车就有人帮拿行李，大堂大气，办理入住井然有序，我非周末节假日去的正好人不算多，亲子房很大，很干净小朋友超级开心，酒店真的有个花园，好多花花草草锦鲤，18米瀑布也是亮点', '2023-02-23', 5, '[''整体满意度'', ''前台服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0231612000apcifcy12AC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232b12000apc0l3eB132_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234312000apcfxrwE80D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237012000apbqzs52707_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间比较满意，对前台工作人员B?tIIy也很满意，很感谢工作人员很热情', '房间比较满意，对前台工作人员B?tIIy也很满意，很感谢工作人员很热情', '2023-09-01', 5, '[''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231z12000c1ro0ne3DED_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店非常的不错，景色很美，设备很齐全！入住的时候看到有小孩，免费给酒店做了升级！', '酒店非常的不错，景色很美，设备很齐全！入住的时候看到有小孩，免费给酒店做了升级！前台Becity Charies态度非常的好！非常不错的体验。', '2023-03-21', 5, '[''整体满意度'', ''前台服务'', ''景观/朝向'']', '["[ \"https://dimg04.c-ctrip.com/images/0236i12000asomfopC89C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '总体体验非常棒的酒店，能感受到丰富的文化底蕴。前台的rivia小姐姐态度友善，脸', '总体体验非常棒的酒店，能感受到丰富的文化底蕴。前台的rivia小姐姐态度友善，脸上永远挂着笑容，耐心的讲解酒店入住的注意事项，还贴心的建议我们尽快去酒廊体验下午茶，替我们担心时间来不及。

酒店处处都是景，负责讲解25个打卡点的老师非常认真细致，让人觉得住在花园酒店根本不需要出门，酒店内的景点就足够你细细品味，博物馆也超出预期，有清晰的参观线索、丰富的藏品和精彩的说不完的背后故事。

两天一晚接近24小时的时间过得很快，我们基本打卡了酒店里所有的景点、餐厅、博物馆、健身房、泳池，这是一座近现代文化交融的酒店，你既能从很多细节中找寻到中国酒店业发展的记忆，也能不经意间感受到酒店努力拥抱现代化、不断创新紧跟时代的步伐，既能体会到成熟完善的硬件设施带给你的处处方便，也能享受到热情体贴的酒店工作人员展现出的人文关怀。这是一座你入住其他诸如万豪、希尔顿、洲际、凯悦等豪华酒店所无法体会到的独特感受，一份只属于广州花园酒店的特别记忆。', '2023-09-17', 5, '[''整体满意度'', ''前台服务'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234q12000c5zp0hfAF98_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233012000c5zrrfwCBDF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234512000c5zoo38AEDF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232412000c5zn38wB67E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常漂亮，感谢Tony给我们做了升房，非常满意的一次旅程', '非常漂亮，感谢Tony给我们做了升房，非常满意的一次旅程', '2023-06-06', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236z2234bfiprpw0BEE7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234z2234bfiprxluD16B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231r2224vc5jplvkDA10_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234h2224vc5jptldB643_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/023522215f8sdnhv5E8F8_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '一进酒店大堂就被震惊了，礼宾部的小哥哥都好热情，服务非常好。酒店的花园超级漂亮，', '一进酒店大堂就被震惊了，礼宾部的小哥哥都好热情，服务非常好。酒店的花园超级漂亮，小朋友每天都要去打卡～', '2023-04-23', 5, '[''前台服务'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236l12000b1h2ped85BC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231v12000b1gwczb44BC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232612000b1h3eua468E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233a12000b1gy72f15D2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231a12000b1gv5xvC195_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236m12000b1gkvza9412_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '让人印象深刻的一次行程。', '让人印象深刻的一次行程。
本来趁着疫情放开，客流不大来广州。
预订了一个套房，三个人，前台的小姐姐还帮我卖做了升级，送了鲜花和宝格丽的礼物。
房间视野开阔，面对着白云山，楼下就是地铁站。
酒店的布局很有特色，院子中有个瀑布，营造了自然的氛围。
庭院小桥流水，曲径通幽，令人心旷神怡。', '2023-02-13', 5, '[''景观/朝向'', ''交通便利性'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232412000anu4chb214B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233412000anugjjg0448_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236q12000anudx3w4407_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235112000anucfmf1317_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236j12000ans2x242F87_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231s12000antco2iC909_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233b12000anu6o2s637F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232f12000anumlnqDD0F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233h12000ansi3987232_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '第一次来广州，选择入住的花园酒店，酒店非常漂亮，因为是金卡会员，还给升级了房间，', '第一次来广州，选择入住的花园酒店，酒店非常漂亮，因为是金卡会员，还给升级了房间，房间很漂亮，又大，晚上去了行政酒廊，体验感非常棒，Zoey,和NIKKI，对客服务热情周到细心，服务非常好，让我以及我的朋友很满意，她们二位的服务让我留下深刻印象。下次来一定还要住你们酒店。

3', '2023-02-05', 5, '[''前台服务'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236g12000aln8fmp366E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234v12000alnhffx3721_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231312000alnq34769BD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232o12000alnoun1E9EE_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州花园酒店的阳台玻璃应该擦擦了 房内射灯一闪一闪的 上洗手间就不能洗澡 洗澡就', '广州花园酒店的阳台玻璃应该擦擦了 房内射灯一闪一闪的 上洗手间就不能洗澡 洗澡就不能上洗手间（就一组推拉门）同样是免费的矿泉水看看万豪 洗澡间顶都掉皮了 早餐葱白还带着根 中国白金五星酒店 就只能看外表了', '2023-02-05', 2, '[''房间设施'', ''卫生状况'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230712000alo4ctw97DE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234f12000alnwjfdB796_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233d12000alnbn3t60DE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236w12000alns6daC07E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234z12000alnyidw71F4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237212000alo44tr10D1_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店虽老一些，但是服务意识特别的好，前台办理入住的小姐姐很有耐心，也帮我们留了高', '酒店虽老一些，但是服务意识特别的好，前台办理入住的小姐姐很有耐心，也帮我们留了高楼层的房间。还送了花和小饼干。早餐特别丰富，整体还是很好的。', '2023-03-19', 5, '[''前台服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231212000asf6qxb29CA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232y12000asf0z9bE9CC_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这个酒店入住给我们留下了非常不好的印象', '这个酒店入住给我们留下了非常不好的印象
不明白为什么会这样
希望管理层重视起来
1，checkin效率低，办理入住30分钟，大厅排队很长
2，2点入住，结果三点半，到酒店告诉我房间没有打扫好，只能先给一间，我们安排老人带孩子先休息，两个人疲惫的在附近转悠了一个半小时（五点）房间还没有打扫好，在我们的争取下给我们安排了顶层，结果房间在消防通道旁边，床很小，设施成旧，没有淋浴间，只有一个老式浴缸，很无语……
3，针对这些问题，酒店没有任何态度，只能说让我们等
携程客服积极的给我们处理了，但是还是有点失望??

客观的说，酒店位置挺好，旁边就是地铁，停车场也挺方便，酒店的花园应该是两点', '2023-02-01', 2, '[''退房/入住效率'', ''房间设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232q12000ak1cec416B0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236s12000ak1ahi471E6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236o12000ak12zl10BA3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230412000ak1cech9B94_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '第一晚订住的大床房有两个问题', '第一晚订住的大床房有两个问题
1、下水道反味 比公共厕所还臭。第二天下午五点换房得以解决。
2、隔音差 隔壁房间孩子的嬉闹声一清二楚。
还好第二天换房得以解决，不然将是一次糟糕的旅程。
酒店亮点：
1、环境优美
2、周围较多老字号餐厅', '2023-02-02', 3, '[''房间设施'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236z12000akdf4zt3EF3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233f12000akdu4ma4476_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236x12000akdkzmp83DD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236612000akdv4oy7AFB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '优点：服务非常好，不愧为广州老牌五星级的酒店。地理位置绝佳，门口就有地铁（5号线', '优点：服务非常好，不愧为广州老牌五星级的酒店。地理位置绝佳，门口就有地铁（5号线淘金站），对面就是广州酒家和白云宾馆，附近步行可到陶陶居，五号线坐五站珠江新城出来就是花城大道，看广州塔夜景的极佳位置。
不足：设施老化，毕竟上世纪八十年代的酒店，不过维护的还可以，也算卫生；早餐品种和质量感觉对不起这个价格和五星级酒店的身份，早餐质量感觉也就国内中档酒店比如亚朵的水平，而且空间很小，八点半后去基本需要排队等座。

整体感觉还是蛮好的，在广州五星酒店里价格相对亲民，应该还会再次选择花园酒店。

祝生意兴隆。', '2023-02-05', 4, '[''交通便利性'', ''性价比'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235u12000alnwi28C0C4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233t12000aln24kvB928_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236x12000alnty7y7F26_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '预订了基础的房型，体验入住感一般。酒店地理位置很好，出行交通方便，门口就有地铁站', '预订了基础的房型，体验入住感一般。酒店地理位置很好，出行交通方便，门口就有地铁站，但对开车客人来说非常不方便，地面停车场每次进出都要去大堂输入车牌号，没人告知过，为此来回跑过两次，而且大堂输入车牌信息的位置经常没人等待很久。
另外这次和家人入住是两晚，第二晚时候突然想在酒店用早餐办理付费过后前台送了几包欢迎小饼干，这欢迎小饼干难道不该在我办理入住的时候送吗？？付完早餐钱想起来自己是岭客汇金卡，但是办理入住的时候并没有升级房型、早餐等服务，经过协商，付的早餐钱退给了我，会员的两次单早并成一次双早。不知道这会员权益是该自己讨还是前台关注的，体验感不是很好。
不过酒店的花园还有博物馆有时间还是推荐逛一逛的', '2023-03-28', 3, '[''交通便利性'', ''前台服务'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0236p12000atjmpo24177_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230712000atjp7125973_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236912000atjo8226AE0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间高度很日式有点压抑，服务很好KRISTT小姐姐主动帮助退房，旁边有很多好吃酒', '房间高度很日式有点压抑，服务很好KRISTT小姐姐主动帮助退房，旁边有很多好吃酒家，下次还会入住。', '2023-04-24', 5, '[''前台服务'', ''周边配套'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230x12000b1p2uom0D85_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233l12000b1phyg10ED5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233t12000b1p8dejFBDB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '第一次住花园酒店，升级了行政套房．房间很大有书房健身房．洗手间也有二间，太棒了，', '第一次住花园酒店，升级了行政套房．房间很大有书房健身房．洗手间也有二间，太棒了，看夜景也很宽阔，卫生干净，服务周到！花园里的风景好看，还有瀑布', '2023-05-12', 5, '[''房间设施'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0230u12000b7d81wo7CDB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236k12000b7dc72b41B5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234812000b7d1ln95D3E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '设施：大气的厅堂，快速的电梯，整体硬件不错。房间比较温馨，略小，尤其是卫生间和淋', '设施：大气的厅堂，快速的电梯，整体硬件不错。房间比较温馨，略小，尤其是卫生间和淋浴间太小了点。
卫生：不错，尤其是9楼打扫的人员总是反复确认要帮忙打扫，假期人多还能这样很赞！
服务：有好有坏，办理入住等待的人很多，有贴心的发小发夹和汽水，缓解等待的着急情绪。办理入住的Ken服务很好，因为是中秋还送了月饼。
不好的地方，下车没有人帮取行李，因为独自带孩子有两个箱子，招呼了门童才不情愿的拿了一下；瀑布餐厅煎蛋的大叔态度不友好，说话阴阳怪气！
早餐：看评论这个酒店是餐饮著称，但遗憾的是早餐很普通，分别在一楼和30楼吃了，没有什么特色，可选的也是有限，8点以后就要排队。早餐最大的亮点是到12点，可以不必太匆忙！
环境：非常好，毕竟叫花园酒店！', '2023-10-06', 4, '[''前台服务'', ''餐饮设施'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235l12000cc5r5jj8D45_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234j12000cc5jyb8F0FA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '一如继往的优秀，主要服务一流，工作人员礼貌客气。地段好性价比高。外国客人很多，酒', '一如继往的优秀，主要服务一流，工作人员礼貌客气。地段好性价比高。外国客人很多，酒店代收了很多快递帮忙整理。', '2023-06-28', 5, '[''前台服务'', ''性价比'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0236f4234bodg3f7431AA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店声名在外，最早的合资五星级酒店，作为广州人的我，竟然到了2023年春节，', '花园酒店声名在外，最早的合资五星级酒店，作为广州人的我，竟然到了2023年春节，才有机会感受她的风采!疫情过后复常神速，从上海回来特地选了她，结果上海话一路不绝于耳，不说地点还以为自己没有离开上海!
Doorman: 有分寸感的礼貌，很好。
Lobby: 很久没有看见这样热闹的节日氛围，喜欢。
Check in: 春节期间超长等待房间已是常态，没办法。
红棉大床房: 房间老旧面积颇大，听说装修排期中。
服务: 我的 Housekeeping 是整个行程的精华，超棒。
饮食: 荔湾亭失望/自助餐无感/酒吧这个烤蔬菜一流。
总结: I will be back! Thank you!', '2023-03-21', 4, '[''整体满意度'', ''客房服务'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232x12000asojozu10FB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234112000asoe5c9832A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234l12000ajiv7ww17CA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235j12000asogtwj523B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店交通出行方便，客房舒适，配套设施齐全，风景优美，中西美食俱全。特别是Caro', '酒店交通出行方便，客房舒适，配套设施齐全，风景优美，中西美食俱全。特别是Carol 小姐很专业，善解人意，喜欢住这里，还会再来。', '2023-10-09', 5, '[''交通便利性'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231z12000cd1qo0f2AD1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235q12000cd1qoql427F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '每次和儿子去动物园都住这里，这次入住太差了，开房门后房间里面还有客户搞的自己马上', '每次和儿子去动物园都住这里，这次入住太差了，开房门后房间里面还有客户搞的自己马上退出来了，换另外一个房间又等半小时而且房间空气清新剂味道太重，五星级就这待遇，如果不是近动物园真心不选择。', '2023-02-22', 3, '[''退房/入住效率'', ''客房服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233g12000apaia7p85C5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230a12000apage7mD3CB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236z12000apa86y07F06_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231j12000apa7rmn6DC5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '在携程花1474元定了该酒店27日入住的64平米的粤韵1.3米双床套房，在前台登', '在携程花1474元定了该酒店27日入住的64平米的粤韵1.3米双床套房，在前台登记入住时说房间没打扫出来，可以免费升级成行政套房，结果该套房又旧又破，沙发又脏又破，马桶老旧，灯好几盏不亮，这种也好意思叫升级房型？这种欺骗消费者的行为，不讲信誉的行为，发生老牌的五星级酒店，真是让心寒。再三协调要求换回原定房型，先是说没有了，晚上七点半再找到经理说，有房岀来，但打扫需要二个半小时，一直到了晚上十一点，孩子已经睡了，只有放弃换房。该酒店这种忽悠消费者，借节假日客房销售旺季，卖老旧客房的行为，让人就像吃了个苍蝇一样恶心。', '2023-01-28', 1, '[''房间设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231k12000aj0zdm4C7D7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234y12000aj12ihb623E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231x12000aj0x4dxBBD1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236g12000aj12roy1490_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233412000aj0yc6gADD4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234s12000aj133812B2D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '超级满意的家庭出行选择。选择花园酒店式最正确的啦，粉色仙女小姐姐也温柔又漂亮，s', '超级满意的家庭出行选择。选择花园酒店式最正确的啦，粉色仙女小姐姐也温柔又漂亮，semmy小姐姐也超级贴心。
卫生：没得说
环境：赞赞赞
春节出行确实人多，早上早餐瀑布酒店人满了，安排我们去荔湾亭吃早餐，更满意的选择啦，中式自助早餐，更熨帖我们的胃。小朋友也很满意。下次还会继续选择这里，哈哈', '2023-01-29', 5, '[''整体满意度'', ''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235512000ajavn084856_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231312000ajawgar6D26_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '春季来广州，各大五星级酒店价格都让人望而却步，叹为观止，只有花园酒店价格还算亲民', '春季来广州，各大五星级酒店价格都让人望而却步，叹为观止，只有花园酒店价格还算亲民??因为分别定的2天，所以房型不一样，客房中心主动帮忙协调???早餐很多人也尽量满足了我打卡的需求??好评??唯一遗憾就是没打卡到米其林餐厅已经约满??', '2023-01-27', 5, '[''性价比'', ''客房服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231312000aitwznfFFD0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232o12000aits923801B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232312000aitt9f7C030_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236612000aitssnq01A5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234s12000aitw6vb3D48_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232z12000aitw8w8ED6E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230g12000aitu6beE7B7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231y12000aituoex2890_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232o12000aittwezE475_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '春节期间服务有点跟不上，但是态度都还挺好的，一开始定的房间来不及打扫给安排了公寓', '春节期间服务有点跟不上，但是态度都还挺好的，一开始定的房间来不及打扫给安排了公寓房，设施可以说非常老旧，难得的是打扫得很干净没有异味，维护的也不错，后面安排到了我自己定的房间还送了三天的早餐，就很好解决了问题。
广州有很多新的高级酒店，但是广州花园酒店的氛围和底蕴是新的酒店无法比拟的，老市区的大花园的即视感，下午茶也很不错', '2023-02-13', 5, '[''整体满意度'', ''客房服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0234i12000anujbew9B20_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232h12000anusl4y2ECD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230v12000anu95wuE6C7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231v12000anuujy2FA6D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234612000antat158A51_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235c12000anu79o8F952_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '性价比很高的一家酒店，客房和礼宾服务不错。一进门就能闻到香香的味道。不过，前台感', '性价比很高的一家酒店，客房和礼宾服务不错。一进门就能闻到香香的味道。不过，前台感觉有点搞不清楚订单情况，我分开预定了2个订单，一个1晚，一个3晚，入住前一天酒店电话我确认了一共2间4晚，办理入住的时候前台说1晚，然后我提醒她有两个订单，才发现是4晚，搞了15分钟吧，当时12点多房间还没打扫出来，我们先外出了，下午2点电话我说可以来拿房卡了，等我4点回来拿房卡，换了个前台，大概又搞不清楚了？又等了5分钟，怎么拿个房卡那么难。。。等第二天游玩回来，进不了房门了，刷不了卡，我猜测真的只做了1晚，但是从头到尾说的都是4晚。吃力。。除此以外其他都挺好的。喜欢酒店内的后花园！', '2023-02-01', 5, '[''前台服务'', ''退房/入住效率'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0232g12000ak1314h2497_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231u12000ak128qsF587_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235k12000ak1cedk2C1E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店超出预期，真的有大花园，自助早餐晚餐都超级棒，亲子套餐下午还送了点心，小朋友', '酒店超出预期，真的有大花园，自助早餐晚餐都超级棒，亲子套餐下午还送了点心，小朋友也非常喜欢房间的布置，整体非常用心，总之下次来广州玩还会选择再次入住！唯一的缺点就是入住率太满，人比较多，春节期间明显人手不够～', '2023-02-01', 4, '[''整体满意度'', ''餐饮设施'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230m12000aju59mb35CB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236d12000aju6nz9BA7B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235d12000aju6mav6EB2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232y12000aju3fu6BA86_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235m12000aju4wlpF198_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235b12000aju6s74A488_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236k12000aju6d4b1C65_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236o12000aju4sm44E06_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236612000aju4qdc1235_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '作为有名的老牌酒店，酒店地理位置非常便捷，建筑和景观设计没的说，非常美。只是设施', '作为有名的老牌酒店，酒店地理位置非常便捷，建筑和景观设计没的说，非常美。只是设施稍显陈旧一点点，虽然看得出是精心设计使用挺便捷，但其实房间小可以不设置浴缸，活动空间会更大。', '2023-03-10', 4, '[''房间设施'', ''交通便利性'', ''景观/朝向'']', '["[ \"https://dimg04.c-ctrip.com/images/0231512000arc1vikD552_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236w12000arbyt6m022B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '本人在当天下午13时左右到前台拿房，下面这个服务员帮我办理，他说，由于节日房间没', '本人在当天下午13时左右到前台拿房，下面这个服务员帮我办理，他说，由于节日房间没打扫卫生，叫我在下午15时到前台找他拿房卡，;我问他说，你来时来到找我就可以了。本人在下午15时到他处，找他拿房卡，他竟然叫我去排队等候，我没排队，叫他找个同事帮我处理，他根本不理我，后来我找到另外一名服务员，拿房不到的原因，是房间没打扫卫生，这样就是酒店的不对了。这就是我们国家的五星级酒店？服务员大冷漠，服务有提升的空间，特别是下面这名服务员。希望携程能了解一下，谢谢。', '2023-01-26', 3, '[''前台服务'', ''退房/入住效率'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230q12000aiid5wb836B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232f12000aiigqh969F1_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '年初三带父母来住，年前预订的时候选择了红棉大床房，订前和酒店电话确认过是可以加床', '年初三带父母来住，年前预订的时候选择了红棉大床房，订前和酒店电话确认过是可以加床的，也在订单的备注里明确要求了。红棉大床有2米宽，我睡加床，父母睡大床，这样父母可以睡的比较舒服。结果在入住前一晚电话告知我有可能无法加床，能否接受换房，我说尽量加床，实在不行换房也是可以的。
到了办理入住的时候前台告诉我床已经不够了，前台给我的选项是1.加钱换粤韵的双床房，现在入住 2.等到四点再入住，到时候电话告知是否有床。如果到时候还是没床就只能三个人住大床房??
粤韵的双床只有1.3米宽，两个成人睡很不舒服。我问前台能不能先保留这间双床房，等到四点能加床就在原房型加床，不能就换到粤韵双床。结果前台告诉我房间是一定不会保留到四点的，到四点也不一定有床可加??
我还能说什么？只能赶紧定下这间双床房。1.3的双床睡两个成人是很不舒服的，晚上父母也并没有睡好。酒店承诺可以加床却无法兑现，也完全没为顾客提供任何解决措施，前台全程冷漠脸，毫无歉意，这就是岭南集团的服务水平？', '2023-01-27', 3, '[''前台服务'', ''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235412000aisc5nrEC60_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230s12000aisbqc0EBFC_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '临时决定到的广州，提前在网上订了住宿，看到推荐，对花园酒店很感兴趣，定了一间红棉', '临时决定到的广州，提前在网上订了住宿，看到推荐，对花园酒店很感兴趣，定了一间红棉大床房。住宿的前一天就接到酒店电话，询问第二天到店时间，以及同行是否有老人孩子。住宿当天下午一点到的，可能春节期间人多，办理住宿真的很耗费时间，前台的小姐姐们都跟有耐心，就是腾房间的速度真的是有待改进。满分送给酒店里所有服务人员，很贴心，很有耐心。酒店房间可以看到后花园，忘了拍照了。早晨睡了懒觉，在荔湾亭用了自助餐，很不错。下次有机会来广州还会选择住这里。对了，离地铁口也很近，很方便。', '2023-01-26', 5, '[''前台服务'', ''退房/入住效率'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0230712000aih0mxc1D48_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234812000aigzz20FB07_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232s12000aih0b5v9F4F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务满意，房间干净，后花园漂亮??', '服务满意，房间干净，后花园漂亮??', '2023-06-17', 5, '[''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0233112000bfohku7822C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境很好。 ', '环境很好。 
 瀑布餐厅自助很美味。尤其牛肉粉很正宗。唯一不足是大堂找点热水让孩子喝，就不给。明明有热水器图七。主要是排队办理入住时间太长，所以想讨杯热水，大堂吧的服务员直接冷脸说没有。2099元的消费瞬间觉得不值了。', '2023-01-24', 4, '[''前台服务'', ''餐饮设施'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0231512000ai11zgb2981_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236612000ai0zpxt7706_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234o12000ai10czb4DE1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231k12000ai11ftx45B5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232912000ai111ws85F9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234812000ai116ziB847_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234b12000ai12beb60B1_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '2016年第一次带孩子入住留下了非常好的印象，所以2023年带家人来广州依然选择', '2016年第一次带孩子入住留下了非常好的印象，所以2023年带家人来广州依然选择这里。虽然酒店设备老旧了一些，但位置、设施、环境卫生等还是不错的。住了六天唯一非常不开心的是房间的安排！带着老人孩子希望两间房间能稍微近一些，被告知过年人太多只能一个安排在18楼，一个安排在5楼，我仔细看订单我定的应该是18到21楼！而且5楼明显和18楼的房间不一样！可气的是办理的前台小哥是不是觉得北方人好糊弄，给我们的房号1847和524，恨不得把不好的房号和房间都安排给我们，因为比较晚了而且带着老人孩子，大过年的也就没有在争论。不会再去了！', '2023-01-29', 4, '[''前台服务'', ''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233612000ajcu93hC37E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235a12000ajcusqf389C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '交通很便利，酒店旁边吃喝玩乐都齐全。春节带家人入住的，大堂里很热闹，浓郁的岭南风', '交通很便利，酒店旁边吃喝玩乐都齐全。春节带家人入住的，大堂里很热闹，浓郁的岭南风情。逛了一圈，是名副其实的花园酒店，房间很大也整洁。特别夸一夸酒店的服务??，因为临走前想吃一回荔湾亭，经理特意帮我们排号，这一趟旅程非常完美。', '2023-02-07', 5, '[''交通便利性'', ''周边配套'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230w12000am8ql1h8322_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231m12000am91zhq5337_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230l12000am8qien30A9_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '金卡会员，办入住的时候说高一级别的房型没房不能升级了，然后我问那加钱可不可以，说', '金卡会员，办入住的时候说高一级别的房型没房不能升级了，然后我问那加钱可不可以，说可以，然后我就说那既然加钱可以升那说明有空房，有空房为什么不能升房？于是说去确认，回来就说满房了，只剩套房，需要补差价1000多。会员赠送早餐只赠送一份，我说那既然升房没有享受早餐不可以多送一份吗？回答不可以，OK，反正后来也没去过行政酒廊了。房间内只放了两瓶水，第一晚打电话让送水和冰块等了很久都没送，再次打电话之后直到睡觉都没有送来，前后等了差不多有一两个小时……第二天打扫卫生非常敷衍，衣物就这样没有叠好直接塞在枕头中间……孩子小尿尿不小心尿到地上，我们自己简单擦了下，但保洁打扫的时候也没有清理干净，总是能闻到味儿??', '2023-01-24', 2, '[''前台服务'', ''客房服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0236u12000ahysjkc7934_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '选了好久，最终还是选择了花园酒店，出门右边就是地铁，去哪里都很方便！从进门门童开', '选了好久，最终还是选择了花园酒店，出门右边就是地铁，去哪里都很方便！从进门门童开始，可以感觉到工作人员很热情，进大厅就看见漂亮的装饰树，虽然人多，服务人员很好，总体给人很温馨的感觉，下次有机会去广州还是会选择他们！白金五星级酒店确实是实至名归！', '2023-01-28', 4, '[''交通便利性'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232e12000aiv585w1A10_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236p12000aiv5a91C3AB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232s12000aiv5m2d6980_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233012000aiv56vbC9B0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店大堂很大气，服务不错。生意较好前台四个接待火力全开也是要排一会队办入住的，地', '酒店大堂很大气，服务不错。生意较好前台四个接待火力全开也是要排一会队办入住的，地理位置很不错，5号线淘金地铁站上来就是，对过广州酒家，侧面点都德', '2023-03-05', 5, '[''交通便利性'', ''周边配套'', ''退房/入住效率'']', '["[ \"https://dimg04.c-ctrip.com/images/0232412000aqnbtg9414C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232y12000aqnbvvoD554_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230r12000aqnbrkq2A69_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230e12000aqnbtgn4AB2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236n12000aqnbtzj3459_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '一个改革开放第一批的五星级酒店，历经40年，能保持这样的状况实在难得，各项硬件还', '一个改革开放第一批的五星级酒店，历经40年，能保持这样的状况实在难得，各项硬件还是很不错，继续加油！软件方面也很好，这次前台的吴灵伶小姐，漂亮又可爱，关键是服务态度超好，热心主动帮助客人解决问题，工作效率很高，非常熟悉各项流程，让客人感觉很舒服。本人从事服务行业的管理工作数十年，像灵伶这样的员工实在是难得，是企业宝贵的资产。', '2024-08-07', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230812000f1f4dpdACB4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235212000f1f4oin98FB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '春节广州到处爆满，选择了花园，虽然做好了老酒店的面积是硬伤的准备，但是这家是1.', '春节广州到处爆满，选择了花园，虽然做好了老酒店的面积是硬伤的准备，但是这家是1.3的床，对带孩子的相对友好，订的是绿意双床。给后面订房的提个醒，1、这个房型的的淋浴必须跨进一个正方形的小浴缸，台阶很高，对小朋友和老人非常不友好。也不安全，不是常规的走入淋浴！！！2.房间不算很旧，但是墙上的插座很多都不好用，床头的那个时钟我住了3天一直7点08！
3.前台的接待办入住也非常的慢！而且没有服务意识和亲和力，一个劲强调需要给他空间！空间！说他墨迹他说嗯，我们是小地方确实慢！广州的是小地方？这是粉刺内含谁呢？
3酒店的瀑布餐厅早餐也不好吃。
4.一楼大堂没有休息区。每次进出酒店大堂都乱哄哄的！
5.周边有广州酒家，利苑，还有其他餐饮选项，如果不赶时间真的不要吃酒店那早餐。。。
6、周边在修地铁去利苑宜安广场需要绕小道步行不远5分钟即可。', '2023-01-26', 3, '[''房间设施'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231112000aik10ip054E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233c12000aijyuvi4DB0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233n12000aik22mz1FD9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231t12000aik1q4a9DE5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '来广州很多次了，第一次入住花园酒店却是因一座有博物馆的酒店，整体感觉非常好。地理', '来广州很多次了，第一次入住花园酒店却是因一座有博物馆的酒店，整体感觉非常好。地理位置好，大堂富丽堂皇，干净卫生，早餐丰盛。当然最值得一提是博物馆啦！附照如下！！！', '2023-03-23', 5, '[''整体满意度'', ''周边配套'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0234j12000asxg2s39FC5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233d12000asx4jo0F069_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231s12000asxhlua5D17_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231r12000asxhz7mF6EB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237112000asx4e0u3E46_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236y12000asx5nbf1906_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236x12000asx5j0gF0AB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236312000asx4sgvA93C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '天呐花园酒店可以说是我住过服务最好的酒店！国内外也住过很多五星，而且都是国际连锁', '天呐花园酒店可以说是我住过服务最好的酒店！国内外也住过很多五星，而且都是国际连锁酒店，但没遇到过比花园服务更好的！！因为我入住时房间有一点异味，前前后后给我打了三次回访电话，第一天就搬来了两台空气净化器，其实在我出去的几个小时里房间已经完全没味道了，酒店还送了我糖和水果。第二天打电话问我是否处理好，还说要送我一个礼物（礼物超级喜欢！谢谢！简直就是猜到我想要什么了），客房服务接电话态度、酒店大堂等工作人员态度都超级好。名副其实宾至如归，以后来广州还住这里！而且位置超级好是我喜欢的老城区，很有老广味道楼下还有很多很多美食。一定会推荐给朋友的', '2023-01-24', 5, '[''前台服务'', ''客房服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234t12000ai220dkDC7C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230y12000ai221zj927C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231q12000ai23i432D99_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235n12000ai23ei6B1EF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州行最后一天（也是除夕这天）入住广州花园', '广州行最后一天（也是除夕这天）入住广州花园
酒店整体新年氛围拉满 各种新春活动

提前两天就有来电确认行程和需求
楼上设置的酒店博物馆 很有情怀（反正很戳我啦）

上榜米其林的早茶-桃园馆 也是很赞 原计划初一这天吃的 没吃成 留点遗憾下次再来', '2023-01-22', 5, '[''餐饮设施'', ''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0230q12000ahlpols2C3F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232q12000ahlohj2BAEA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236k12000ahlpytp6013_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235q12000ahlpm9pC56B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235e12000ahlpzqcC6C3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234512000ahlpcgs3A03_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230i12000ahloxi10C02_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '很庆幸春节期间选择了这家酒店，十足的年味，整个大堂都充满了节日的喜庆，酒店做足了', '很庆幸春节期间选择了这家酒店，十足的年味，整个大堂都充满了节日的喜庆，酒店做足了功夫，小朋友们都特别喜欢在大堂里玩，大年初一的早上还在酒店门口和大堂里看到了正宗的舞龙舞狮表演，酒店内部还有一个花园，瀑布，周边吃饭也很便利，点都德和广州酒家步行可达，门口就有地铁，出行也很方便。老牌酒店，精于管理，是不可多得的好选择。', '2023-02-08', 5, '[''整体满意度'', ''周边配套'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0230c12000amkcfsn1D69_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235w12000amkcph3C59A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '元宵节前特意坐高铁从深圳来到广州入住花园酒店。去年10月中旬入住时对酒店的行政酒', '元宵节前特意坐高铁从深圳来到广州入住花园酒店。去年10月中旬入住时对酒店的行政酒廊体验很好，所以这次特意选择了可享用行政酒廊的大床房3晚。入住办理、出入开门、行李存放等服务都很到位。大床房内饰、床寝用品、卫生洗浴等设施都令人舒适应手。不巧的是浴室的下水道不很通畅。中午洗澡后流水满地，尽管浴房玻璃门外有地垫，但水还是流到了卫生间和门廊。我们午休1个多小时后积水仍在。如果只住一晚将就一下算了，可是要连住3晚，万一滑倒了周围不是玻璃就是浴缸，地面又是大理石，都不是一件小事，可谓有严重的安全隐患。于是把地面两处的积水拍照后去大堂前台商量能否换一间房。令我想不到的是大堂经理YANNIS范认真耐心听取了我的诉求，留存了我出示的两处积水的照片，很快同意并落实了换房。我们被免费换到了楼层更高，设施更优，面积更大的红棉大床套房。真的被YANNIS范经理的至真至诚的处理结果暖心和感动到了。在此，为她的处理偶发事件的能力、水平和智慧点赞！也为她的果断、魄力和大气格局点赞！再次感谢YANNIS范经理！酒店行政酒廊的早餐、下午茶、欢乐时光的出品、环境、服务一如既往的好。特别点赞早餐。自助+点单、即点即做的模式与上海的J酒店上海中心的早餐模式一样一样，真的令我惊喜和满意。中西式早餐出品比瀑布餐厅的全自助早餐精致优质很多。说实话，行政酒廊的早餐优于自助早餐在酒店行业很少见。我们3天的早餐后面两天都选择了行政酒廊。印度藉服务员CARRIE中文讲得好，服务很主动很勤快很热情很nice。元宵节那天酒店早餐没有汤圆，行政酒廊的欢乐时光也没汤圆，我在向CARRIE询问时随口说了一句：特意来花园酒店过元宵节，没想到在酒店吃汤圆反而成了一种奢望。不一会CARRIE送上来两盅红豆沙芝麻汤圆，真的令我们很惊喜。CARRIE说她和同事把我们的询问和需求反馈到了酒店中餐厅，那里特意为我们做了这两碗汤圆。我和先生听了都非常非常感动。在此，特别感谢中餐厅的后厨师傅，谢谢！辛苦了！也特别感谢印度藉服务员CARRIE，谢谢你的用心和勤快！你们的优质服务让我们度过了一个很美好又难忘的元宵节。细节决定未来，服务决定高度。服务的灵魂是真诚。花园酒店注重细节服务真诚，非常值得入住体验。强烈推荐！', '2023-02-09', 5, '[''前台服务'', ''餐饮设施'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231q12000amss00nCADE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233912000amsq1lo1FDA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233912000amssv01BB38_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235o12000amskyf82A52_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230c12000amsxozz6A36_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234r12000amsnuda87C2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234p12000amszxv28641_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235l12000amszxv30716_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233112000amt9c6p9DFD_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '春节渡假全家打卡白金五星，连住四晚总体失望，不会再来。房间与快捷酒店同一档次。大', '春节渡假全家打卡白金五星，连住四晚总体失望，不会再来。房间与快捷酒店同一档次。大堂乱糟糟的有壁画给个四星吧。后花园终于有五星的感觉。春节来也不能要求太高，前厅部与餐饮部很热情。客房部感觉人手不够。礼宾部冷漠，门外的门童直接摆烂，建议调去客房部。对携程铂金没有任何礼遇，春节不差携程这点客流吧。', '2023-01-26', 3, '[''前台服务'', ''客房服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234g12000aikisn19179_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236i12000aikizb09918_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '来之前是先预定的白天鹅，抱着电话咨询下的想法联系了花园酒店，没想到一个电话让我退', '来之前是先预定的白天鹅，抱着电话咨询下的想法联系了花园酒店，没想到一个电话让我退掉了白天鹅入住花园酒店，事后觉得自己非常英明！从电话预定到入住直到离店，所有的过程都非常完美，哪怕是春节期间细节都做得非常好，从进酒店一刻感受就是宾至如归，清理阿姨态度尤其好，没有评论说的不多给水的事情，只会多给你！总之非常完美，下次还要入住', '2023-01-25', 5, '[''前台服务'', ''整体满意度'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0237012000ai9c6w9DCC1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230q12000ai9d05z5F1C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '愉快的入住＆用餐体验，不愧是白金五星级的花园酒店~前台Joyce和Cecilia', '愉快的入住＆用餐体验，不愧是白金五星级的花园酒店~前台Joyce和Cecilia服务态度好好哦，给的小羊和冰箱贴可可爱爱，无论是check in还是咨询都是亲切又有耐心?? 路上遇到Patrick，指引很到位??总机Dany还有Lydia声音温柔极了，好好听~最后遇到的粉色小姐姐Rain，快捷退房太太太方便啦~', '2023-07-26', 5, '[''前台服务'', ''退房/入住效率'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236s12000br43ti530F5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230712000br3wcglBCD0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233b12000br482r44BCA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232x12000br3wxvc3AA1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232o12000br3x6xeAB83_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230f12000br45lb1A5FD_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次出行的惊喜，是花园酒店给的', '这次出行的惊喜，是花园酒店给的

设施：应该是刚装修不久，整个酒店看起来还很新。能免费停车，酒店的游泳池和健身房的设施也不错

卫生：每天上午打扫很及时。

环境：春节的氛围感简直不能更赞了，大年初一还有舞龙舞狮表演

服务：服务很贴心', '2023-01-24', 5, '[''公共设施'', ''客房服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234x12000ahlrrpk22C4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237112000ai15z30831C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232g12000ai1424m8C37_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233a12000ai14j3nDA92_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌五星酒店，花园真的很美。服务人员都很热情，办理入住时TONY MAI 很周到', '老牌五星酒店，花园真的很美。服务人员都很热情，办理入住时TONY MAI 很周到，看到带着小孩，会体贴的送上小饼干，孩子很开心。', '2023-03-15', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232z12000arxfp0aB44A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236812000arxa4qc7155_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务非常好，不愧是老牌酒店；春节期间入住，大堂每天都有各种吸引小朋友的表演，最爱', '服务非常好，不愧是老牌酒店；春节期间入住，大堂每天都有各种吸引小朋友的表演，最爱小丑表演，对小朋友很有爱；房间有点局促，但是该有的设施都一应俱全，客房服务非常温馨，一点点小建议，退房能否给个快速通道，和入住客人一起排队很慢，中间还有插队办理的，这方面管理有待提高。', '2023-01-27', 5, '[''前台服务'', ''退房/入住效率'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0230v12000aiozsphBAA5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234r12000aioyo1r6459_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235a12000aioyer91CEA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常喜欢的', '非常喜欢的', '2023-07-09', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232x12000bm6wvbj7176_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '带爸妈来广州过年，入住花园酒店。第一眼有被酒店大堂惊艳到，背景墙上的红楼梦人物图', '带爸妈来广州过年，入住花园酒店。第一眼有被酒店大堂惊艳到，背景墙上的红楼梦人物图金碧辉煌，衬着火树银花相当气派且有氛围。我们订了三间房，个人感觉红棉大床房性价比最高，面积也很合理。小套房设计孩子睡觉不会被打扰，二米床适合三口之家。淋浴浴缸都有。虽然设备有些老旧但总体住的还是很舒适的。酒店就在五号线淘金站出口，对面就是友谊商城，广州酒家（有个地道可以过，不用走天桥）。进出非常方便。酒店的服务也很好，工作人员都很热情。是这次很愉快的住宿体验。建议: 换床单被套，和换浴巾可以分开选择。我不需要每天更换床品，但用过的浴巾需要更换一下，但感觉只能全换，或者全不换。马桶间缺一个可以放手机的架子。', '2023-01-26', 5, '[''性价比'', ''交通便利性'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233e12000aike4r4A705_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232h12000aikdoi31C99_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235m12000aikejc1A147_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230u12000aikdq7m20F7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店是老牌的广州五星级酒店，对它还是充满了期待，但入住后发现浴室毯子上明显的', '花园酒店是老牌的广州五星级酒店，对它还是充满了期待，但入住后发现浴室毯子上明显的一戳头发没有打扫掉，卫生间的边角还有抽屉里都有散落的头发没有打扫干净，对于细节上的处理还是比较失望。酒店的花园是亮点，服务也没啥问题，在酒店荔湾亭吃了中饭感觉也不错值得一去。这次春节假期，酒店在年初一还搞了醒狮活动，非常棒，让我们体验了岭南文化和广州过年热闹的节日气氛。希望酒店能在细节上更完善，毕竟细节才是真正体现酒店的管理和质量！', '2023-01-27', 4, '[''卫生状况'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234i12000aiqey6rAD2D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236212000aiqgx8lAAC4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236m12000aiqf59573FC_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '很意外的收获！特别满意的一次入住，酒店前台的帅哥Billy很客气的帮忙升级了房型', '很意外的收获！特别满意的一次入住，酒店前台的帅哥Billy很客气的帮忙升级了房型，广州历史悠久的大酒店，没有一点陈旧的感觉，干净卫生！这次是晚上入住，一大早就退房了，没来得及体验餐厅的美食和后花园的美景。', '2023-02-23', 5, '[''前台服务'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0230112000apcvhpb6341_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231412000apcv3ms62D6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235i12000apck134BA76_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231a12000apcol2h4AE3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235a12000apcuv0pBA88_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236f12000apctrqj75C1_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '地段不错，出行方便。后花园环境值得观赏。整个酒店服务算中等。不方便的地方有两个，', '地段不错，出行方便。后花园环境值得观赏。整个酒店服务算中等。不方便的地方有两个，一是停车每次出场均要和礼宾部说，二是作为南方的星级酒店，客房里长供两瓶350ml矿泉水，是不是有点少了，虽然每次找前台要，都能很快送来，是不是可以综合记录下客人需要，以便精准服务，提升体验。', '2023-01-26', 4, '[''交通便利性'', ''周边配套'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232y12000aiild58E09F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230n12000aiin5cbF3DE_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '优点：环境好，服务有好有坏吧，整体还不错', '优点：环境好，服务有好有坏吧，整体还不错
缺点：1，设施老化严重，房间内老旧，衣柜换了2房间还是关不严，导致衣柜灯光一直亮很恐怖，总感觉会出来咒怨。2，荔弯亭前台接待，地域歧视，对北方人态度特别差，不仅丑而且说话也不好听，真想骂她。', '2023-01-22', 2, '[''房间设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236612000ahle1br3D57_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '舒适、卫生、方便', '舒适、卫生、方便', '2023-06-30', 5, '[''整体满意度'', ''卫生状况'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0230312000bjddxda0B45_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '超级满意???? 下次还来??', '超级满意???? 下次还来??', '2023-06-20', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236l12000bgjhkr96521_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235s12000bgjslhvA086_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236l12000bgjgk234093_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '隔了37年再次入住花园酒店，往事历历在目，感谢花园的花园还在，假山瀑布依旧，看到', '隔了37年再次入住花园酒店，往事历历在目，感谢花园的花园还在，假山瀑布依旧，看到跑来跑去的孩子们的笑脸，和当年的自己重叠。祝愿酒店历久弥新，带着岁月的庄重和沉淀，永远保持年轻，永远进步。', '2023-01-29', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232s12000aj8cen62283_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236612000aj8at2079C4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236c12000aj89a9yB220_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231912000aj8etgz6DD5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常干净，很有岭南文化韵味，可惜时间紧张，有空再来研究，感谢前台KiKi的帮助。', '非常干净，很有岭南文化韵味，可惜时间紧张，有空再来研究，感谢前台KiKi的帮助。', '2023-05-16', 5, '[''卫生状况'', ''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235h12000b8bp0b8757F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232m12000b8bjkc80208_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236912000b8bo6pcBC85_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌五星酒店是不错的，位置也方便，地铁站出门就是，环境也很好，只是前台办理入住比', '老牌五星酒店是不错的，位置也方便，地铁站出门就是，环境也很好，只是前台办理入住比较慢，另外浴缸是坏的，排水阀有问题不能用，孩子每天玩累了想回来泡一泡澡都不行，住了三天都没给解决，有点扫兴了', '2023-01-29', 4, '[''房间设施'', ''前台服务'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0235712000aj716fwB31F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230x12000aj75icl5DCD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232412000aj73oa1A408_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '入住花园酒店，真的感觉到老五星的大气高端，金碧辉煌。服务生客气的为您开门问安，感', '入住花园酒店，真的感觉到老五星的大气高端，金碧辉煌。服务生客气的为您开门问安，感觉宾至如归，很舒服。再去品尝二楼的米其林Stiller，菜品服务都没的说。', '2023-02-18', 5, '[''整体满意度'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233012000aorze0l25DB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231h12000aorzenf0277_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236n12000aorze1d9648_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231d12000aorze1s9872_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235e12000aorzfb5D8F8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233812000aorzi2o928F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234k12000aorzfbk9AB0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230w12000aorzhixC049_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235y12000aorzi373A73_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '中秋国庆双节出游，一家三口选择广州花园酒店，连续住了2个晚上，感受超五星服务，感', '中秋国庆双节出游，一家三口选择广州花园酒店，连续住了2个晚上，感受超五星服务，感谢前台胡女士给延后退房，入住有送月饼，退房送化妆品！', '2023-09-30', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231112000cagjkk1114F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234i12000caghgxx1851_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230312000cagnjj456AB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233s12000cagbn7k17B6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230312000cagj9p0355B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230312000cagkg2d239B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '前厅何小姐服务非常好！酒店环境也很不错，非常适合一家出行居住！', '前厅何小姐服务非常好！酒店环境也很不错，非常适合一家出行居住！', '2024-06-25', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230r12000ekitod46797_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236812000ekiwalhFC3D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230g12000ekj077k4648_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231g12000ekixn2v90AA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '度周末再次选择大羊城 是因为花园酒店', '度周末再次选择大羊城 是因为花园酒店
先不说花园酒店是中国唯三的白金五星级饭店 也不说花园酒店是世界知名建筑设计师设计 前国家主席奠基 第二代领导核心题名等这些皇冠 这些光环在我看来 跟大家喜欢的只是奥运冠军 而不是喜欢这个运动本身一样的道理 所以 我不想说
这次我想说一下我对于酒店的个人见解
在传统观念当中 酒店只是我们到另外一个城市需要晚上住宿的地方 随着我的出行越来越多 具有精准定位 独立设计 独具匠心 具有内涵 体验美好的酒店也慢慢成为了我的目的地之一
这些酒店所散发出来的吸引力不仅仅是一种对于酒店或者旅行的情怀 更多的是渗透于生活当中的延绵沉淀 现在已经慢慢成为我的一种生活方式 简单点说 就是吃美食 耍酒店
关于花园酒店建筑本身的一点思考
花园酒店是贝聿铭先森指导的 贝先森是美国宾夕法尼亚大学建筑学毕业 作为华人的贝先森在中国有很高的知名度 我见过贝先森的作品 例如香港????中银大厦 但我还没去过法国巴黎卢浮宫 花园酒店在差不多四十年前就建造完成 今天仍然洋气 理念仍然先进 细节仍然到位 在其作品中体现得淋漓尽致 其实本质就是更早的接触了现代文明', '2023-01-31', 5, '[''整体满意度'', ''房间设施'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232c12000ajqlic1EA88_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234w12000ajqnhct9566_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234g12000ajqllq10666_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '很好的一次入住体验 凌晨的时候入住工作人员还是很热情很细心，房间的环境设施都很满', '很好的一次入住体验 凌晨的时候入住工作人员还是很热情很细心，房间的环境设施都很满意，床对于我来说有点软但是朋友觉得很舒服很满意。
就是地下停车场不大好找绕了两圈进去问了工作人员才知道在哪 然后早上忘记要停车券 想想算了付了50停车费 btw整体五分确实值得', '2023-01-15', 5, '[''整体满意度'', ''前台服务'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235012000ag1z11p3209_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234d12000ag1zysd7071_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236r12000ag20txxB308_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌的五星级酒店，设施有些年头了，办入住给免费升级了套房。还免费加了一个床。马桶', '老牌的五星级酒店，设施有些年头了，办入住给免费升级了套房。还免费加了一个床。马桶声音有点大，卫生有带提高。酒店的床垫是很舒服值得入睡的，在携程定的双早，到行政酒廊用早餐说服务员说只有一位，瞬间心情就不太好，最后沟通还是去吃了早餐的，早餐种类较少，味道还可以。水果nice、尤其是蓝莓很好??。不明白酒店内部的各个部门有什么问题没有沟通好。原本还打算周六继续订房住的。现在还在还在纠结中….', '2023-01-12', 4, '[''房间设施'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0206m12000aff3juoE325_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0203512000aff2yln7117_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0203a12000aff3n8b12F5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '刚入住时候没有强调自己的明确需求、被前台安排了边边房，很是生气??立马下楼联系经', '刚入住时候没有强调自己的明确需求、被前台安排了边边房，很是生气??立马下楼联系经理换房??定了双床后台却显示大床，搞了乌龙，只能再换一次，最后由于他们的失误让我耽误了那么久才入住，免费给我升级了大房双床！很是喜欢！舒服！自助餐品种确实不多、但能吃饱，要求不高哈哈哈，里面的花园真的绝了！满满绿植～设计的好赞！', '2023-01-12', 5, '[''前台服务'', ''退房/入住效率'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0206712000afe83rq65D6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0204l12000afea0vo096B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0205912000afebd2f3364_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0206g12000afeao825DC7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '评分真的很水，最多就是个快捷酒店的样子，跟五星一点也不沾边，卫生太差，尤其是马桶', '评分真的很水，最多就是个快捷酒店的样子，跟五星一点也不沾边，卫生太差，尤其是马桶，层高和低，很压抑，装修老旧，瀑布餐厅的早餐纯属噱头，种类少且难吃，并且也没有什么景观，踩雷', '2023-01-31', 2, '[''卫生状况'', ''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232a12000ajs8eis5ECF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230s12000ajs8b5jD266_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230q12000ajs6v0t1D94_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235912000ajs4lbb1E58_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235212000ajs66i11296_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间不大，设备旧了，但保养很好，服务在线！其酒店的餐厅更是顶流！下次去广州还回去', '房间不大，设备旧了，但保养很好，服务在线！其酒店的餐厅更是顶流！下次去广州还回去！', '2023-04-15', 5, '[''房间设施'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234212000aynu6ry7392_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233r12000aynwdzdB05C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236112000aynskv6965B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237112000aynuabtB701_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235v12000aynu9i8C7D2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234y12000aynu6s00E88_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236012000aynt9ysABDC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232j12000ayo7eol5300_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236512000aynok095CF5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '前台大堂的员工都给人一种宾至如归的感觉，特别是前台带人办理入住的粉色衣服的几个小', '前台大堂的员工都给人一种宾至如归的感觉，特别是前台带人办理入住的粉色衣服的几个小姐姐们超有礼貌的。
服务一流的花园酒店，基本上想要什么都可以商量着来。
设施都是新的，酒店装修复古，但住下却有家的感觉，很喜欢。', '2023-01-19', 5, '[''前台服务'', ''整体满意度'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231s12000agu7mhsAB7E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230f12000agu4jzbDD14_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232v12000agu3znj05C5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '干净卫生，地理位置很好，出门就是地铁，有商场，去哪里都方便，有很多外国人！服务也', '干净卫生，地理位置很好，出门就是地铁，有商场，去哪里都方便，有很多外国人！服务也挺好，有浴缸，酒店比较有广州特色，据说是白金5星，适合商务出差，一楼有很有名的瀑布餐厅', '2023-02-04', 5, '[''交通便利性'', ''周边配套'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0205o12000al5zma26765_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0230f12000al51msdFB5A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232312000al47hu009FB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233i12000al4mfun4B8F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店装修有特色，前台接待Tony服务态度很好，点赞！', '酒店装修有特色，前台接待Tony服务态度很好，点赞！', '2023-05-14', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230q12000b7syi4f68BA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236612000b7s43692F44_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232u12000b7s8ycr47EB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '又来花园小住，放开后的花园酒店又恢复了往昔的繁荣，有人气多了，希望新一年越来越好', '又来花园小住，放开后的花园酒店又恢复了往昔的繁荣，有人气多了，希望新一年越来越好。
小雨中的花园，又是另一翻味道，小桥流水配上毛毛细雨，更像仙境了。酒廊还是一如既往的出色，虽然人多了一点，不过服务还是很好，尤其感谢Yannis和Candy的照顾，下次会再来。', '2023-01-13', 5, '[''整体满意度'', ''公共设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232t12000afpzpr1E3B4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州入住最满意的酒店了，套房很舒服?? 还有点心赠送。行政酒廊服务不错，早餐很好', '广州入住最满意的酒店了，套房很舒服?? 还有点心赠送。行政酒廊服务不错，早餐很好吃。本来想吃荔枝湾的，但被告知晚上没座位了，可惜。于是去对面广州酒家，结果踩雷了，不建议大家去。。。', '2023-01-26', 5, '[''整体满意度'', ''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0203h12000aig32649C92_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0205412000aig30222378_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0201l12000aig353b5461_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0200512000aig5n0cE7F8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0200x12000aig32k19EB6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0207312000aig3x5yE04F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次带家人来广州玩几天，主要是逛逛老城区，品品老广美食，最终选择入住花园酒店。', '这次带家人来广州玩几天，主要是逛逛老城区，品品老广美食，最终选择入住花园酒店。
酒店地理位置很好，步行100米就是淘金地铁站，去哪里都非常方便。
酒店虽然开业几十年了，但翻新之后还是很不错，设施齐全，服务非常热情。入住赠送了双人行政礼遇，非常贴心。
这次行程时间紧，酒店的米其林餐厅也没来得及细细品尝，下次来广州我想还是会选择这里。', '2023-01-16', 5, '[''交通便利性'', ''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231y12000agatyrz97CB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236412000agavf3f42FC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234u12000agawcb6C6E7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230412000agavext1914_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230r12000agav7mr0C4C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235l12000agav69p7AD0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236x12000agavnw1530F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌酒店，内部设施很老了，满满的年代感，散发着历史的味道，服务还是不错的，房间卫', '老牌酒店，内部设施很老了，满满的年代感，散发着历史的味道，服务还是不错的，房间卫生可以再改进一些。携程白金卡和岭南汇金卡互通，给升了房，送了行政机遇，虽然吃的很一般，但是可以在花园里喝茶吃蛋糕看孩子两不误也挺好的，很超值。', '2023-01-11', 4, '[''性价比'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0231z12000af9zow85142_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231m12000af9zwra4311_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233j12000af9zpgl6E77_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236v12000af9zy9z5AF1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230k12000af9zy44EA4B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '宝藏酒店-广州花园酒店，很久不曾住在广州的内城，楼下的人群摩肩接踵，酒店大堂就像', '宝藏酒店-广州花园酒店，很久不曾住在广州的内城，楼下的人群摩肩接踵，酒店大堂就像个热闹的集市，绝美的花园，如果喜欢锦鲤几乎可以盯着花园溪水里的锦鲤看上半天时光，包罗世界美味的酒店餐厅，而且一间酒店里最多家米其林餐厅的，可能就是花园酒店里，不同于珠江新城的四季，柏悦，瑰丽，80年代的老酒店，有着独特的味道
特别讲前台接待小胡，知道我们第一次入住特别的介绍了一下酒店，马上就有了好感，特意安排了别具岭南特色的房型，很感谢啦', '2023-03-23', 5, '[''前台服务'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231412000asv6ruv8AFC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234w12000asv7jnnE787_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235i12000asv0p861F3B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232s12000asuyy6v8944_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232q12000asuyi8u3A34_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233412000asv3xstFC22_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233e12000asv1wbu72D5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233s12000asv501140A8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237112000asv5pll9C82_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常满意的一次旅行住宿！不愧是广州著名的酒店，服务热情周到。入住当天，前台Wen', '非常满意的一次旅行住宿！不愧是广州著名的酒店，服务热情周到。入住当天，前台Wendy 十分贴心地为我们升级了行政商务套房。晚上在锦鲤行政酒廊，体验欢乐时光。酒廊就在内花园，安静优雅。酒廊的Katherine 很暖心地送给我又一份欢乐体验，品尝美点。让人难忘的一次五星级的享受??', '2023-03-07', 5, '[''前台服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235v12000aqytu11E184_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236b12000aqyfhs477CE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233912000aqyoiq31323_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233212000aqyn35u928C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233q12000aqyk4xyE3C1_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店很气派，房间卫生一般，服务还行，早餐品种单一，但是果汁都是nfc果汁，酸奶也', '酒店很气派，房间卫生一般，服务还行，早餐品种单一，但是果汁都是nfc果汁，酸奶也不错', '2023-04-10', 5, '[''卫生状况'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233g12000awef0yv4745_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', 'kiki Kristy 服务很好，酒店环境不错，推荐推荐！', 'kiki Kristy 服务很好，酒店环境不错，推荐推荐！', '2023-05-03', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230p12000b58nl96C47E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '很有气质的一个酒店 满意的体验', '很有气质的一个酒店 满意的体验', '2023-06-02', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235212000bcctb1q6841_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235y12000bcctk2p6A65_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230i12000bcctrg24177_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '不愧为中国三大白金级酒店之一，环境优美，有花园和博物馆可以参观，服务热情贴心，早', '不愧为中国三大白金级酒店之一，环境优美，有花园和博物馆可以参观，服务热情贴心，早餐丰盛美味，除了床有些软，住感几乎完美。', '2023-03-09', 5, '[''整体满意度'', ''餐饮设施'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236712000ar94dz5FF9D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234t12000ar8oqmf5573_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235y12000ar8sd3n62B5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231k12000ar92kna1500_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '必须要给酒店一个大大的好评，尤其是前台一位染了头发的个子高高的男生（抱歉忘记了他', '必须要给酒店一个大大的好评，尤其是前台一位染了头发的个子高高的男生（抱歉忘记了他的姓名）和当时在的主管。
我当时通过携程订的房间，到达前台的时候因为晕机+晕车非常不舒服。结果携程的预订出了问题，当时前台查不到我的订单。这位男生帮我查了很久，看我不舒服先请我在旁边坐下。后来联系携程，好容易订单重新弄好后居然又把我姓名弄错。折腾了好一阵才弄好住宿。
这位男生从头到尾态度非常好，看我带着行李和娃，还有送水。后来还请示主管帮我把房间升级，也送了小礼物。整个过程前台的男生和主管态度都非常好。其实这本来完全不是酒店的问题，但是酒店的态度实在是很令人满意。
于是后来我取消了原本订好的酒店，续住下去。
酒店本身其实有点老，但是交通的确非常方便。周围美食也很多。
后来走的时候又忘记东西在酒店，酒店也专门发了短信来提醒。
服务足以弥补硬件的问题。
酒店的洗漱台非常有特色，在极其有限的空间里营造出了德罗斯特效应。', '2023-02-13', 4, '[''前台服务'', ''交通便利性'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0231n12000anycbff4562_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230712000anyiean1C95_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234h12000anyf59uD31F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '作为一家改革开放后的酒店，有近四十年的历史了。服务有程序有规范，设施有做了升级，', '作为一家改革开放后的酒店，有近四十年的历史了。服务有程序有规范，设施有做了升级，交通也方便，地铁、巴士都在大门口近旁。', '2023-03-18', 4, '[''交通便利性'', ''前台服务'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235n12000as8tqfdABB1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233s12000as89nmvF2A9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230912000as885000EF0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232k12000as8bi8w408D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236a12000as88l5j3586_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店自带博物馆，每个餐厅都很网红。春节期间人非常多，但是办理入住还比较人性化。', '酒店自带博物馆，每个餐厅都很网红。春节期间人非常多，但是办理入住还比较人性化。
  行政酒廊不错，酒店自带瀑布，可以打卡拍照。后花园有许多锦鲤可以喂养。', '2023-02-18', 5, '[''公共设施'', ''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0233h12000aop2usn0B7F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235712000aopbkyhDC6E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234d12000aop2uso9006_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235a12000aopg0dc1966_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233w12000aopjw2iA648_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233y12000aop9vi4FC18_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233o12000aopcsc1C1ED_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230812000aopixgu7513_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236312000aopbkyiF943_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '体验很好的一次住宿经历，酒店年味很浓，一进大堂就充满浓浓的年味，让我们大年初一从', '体验很好的一次住宿经历，酒店年味很浓，一进大堂就充满浓浓的年味，让我们大年初一从外地来广州度假的人员感觉像过年，服务员态度很好，酒店一楼瀑布餐厅很有特色，景色好，胃口都好了。', '2023-01-24', 5, '[''整体满意度'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236b12000ai11d4k4F35_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233c12000ai13ixb5249_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233612000ai13rh73443_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234n12000ai14mffCEF2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231o12000ai13s9eDEB2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231212000ai11q1w62FC_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '每次到广州习惯入住这里，服务很周到。', '每次到广州习惯入住这里，服务很周到。', '2023-06-18', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231012000bfv2mx21F2A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231c12000bfuv1k1B9D8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231712000bfuxyp5F063_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233a12000bfutwfwC73C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231w12000bfuy2gv8734_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230n12000bfuxae2726E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '在广州过春节第一站，前台小哥给升级了房间（低价有偿），大堂里春节气氛浓烈，酒店门', '在广州过春节第一站，前台小哥给升级了房间（低价有偿），大堂里春节气氛浓烈，酒店门前有地铁出行方便，最好的地方就是酒店周边步行10分钟内有点都德和陶陶居，咱到广州不就是为了吃嘛！', '2023-02-08', 5, '[''周边配套'', ''交通便利性'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232612000amj0ceeCE94_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235012000amj1zifA4CD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236f12000amitrqm2538_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236m12000amim1qmC20F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232112000amisxpb8B0A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '设施：大厅非常具有老牌五星酒店的霸气感觉。', '设施：大厅非常具有老牌五星酒店的霸气感觉。
卫生：中规中矩。
环境：绝对是非假日酒店界的NO1。感觉比一些假日酒店还好。
服务：几个外籍服务员态度还是不错的。
尊享行政礼遇（包含下午茶和欢乐时光）:绝对超值！必须定！必须定！必须定！', '2023-01-14', 5, '[''整体满意度'', ''性价比'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0204n12000afumv1c7961_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0203m12000afundjrAEA2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0205r12000afuptgi1054_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店服务到位 感谢tony老师办理入住速度很快 酒店博物馆和岭南花园是亮点', '酒店服务到位 感谢tony老师办理入住速度很快 酒店博物馆和岭南花园是亮点', '2023-06-18', 5, '[''前台服务'', ''退房/入住效率'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233112000bfztmyeC7C5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '从小就听说过花园酒店，这次来广州终于住过了。套间里面设计，装饰和家具还都很新，服', '从小就听说过花园酒店，这次来广州终于住过了。套间里面设计，装饰和家具还都很新，服务员都主动打招呼，酒店春节期间也装饰的新春喜庆。特别喜欢花园酒店，下次还会来入住。', '2023-01-29', 5, '[''整体满意度'', ''房间设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234012000ajd0g3vD8F5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230d12000ajd33yvD41E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230912000ajd3bnr7275_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230t12000ajd03qv297E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236z12000ajcz0mx33A7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236w12000ajd0ijaCC4A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235l12000ajcz207E2F9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233g12000ajcyeizCC5A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232p12000ajd2uq085DC_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店大堂很奢华超级气派，有红楼梦金箔墙，在瀑布餐厅用自助餐198一位蛮好的??我', '酒店大堂很奢华超级气派，有红楼梦金箔墙，在瀑布餐厅用自助餐198一位蛮好的??我们的房间套房住着很舒服，出行很便利哦！', '2023-03-12', 5, '[''公共设施'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0204412000armcb5c064D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0206k12000armjc10FD6C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0205a12000armchj4D221_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0203n12000armca6c44C1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0204s12000armfiif3E9C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0201q12000armf42aDBE5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0202m12000armf42b3658_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0202y12000armbigo35E5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0205g12000armix0a57DE_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '有休息厅，房间干净整洁，服务员服务专业，办理入住的帅哥，靓妺很耐信，易于沟通，因', '有休息厅，房间干净整洁，服务员服务专业，办理入住的帅哥，靓妺很耐信，易于沟通，因要续住一天，Betty的处理方法很暖心，非常感谢！以后出差，旅游还会考虑入住！', '2023-12-10', 5, '[''前台服务'', ''客房服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0230o12000cpl4ym1F23D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236e12000cpl3tzr7227_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233d12000cpl3ly8BD76_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店本身的历史文化很丰富，是全国3家白金五星级酒店之一，有自己的博物馆，还有4家', '酒店本身的历史文化很丰富，是全国3家白金五星级酒店之一，有自己的博物馆，还有4家米其林餐厅，可惜只体验了荔湾亭，所有的工作人员都很热情和亲切，交通很便利，去哪里都方便，不足的自助餐没什么吃的。小插曲是瀑布餐厅2次把我们房间包含的自助餐人数弄错，就有点无语，不知道为啥会这样
