ments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '很高兴这次来广州选择了花园酒店～ 很有历史沉淀感的酒店，后花园非常漂亮，名副其实', '很高兴这次来广州选择了花园酒店～ 很有历史沉淀感的酒店，后花园非常漂亮，名副其实的花园酒店，Billy替我们办理了原房续住省去了我们换房间的麻烦，特别感恩感谢～ 感受到了广州人民的友好与好客，会推荐以后来广州的朋友入住此酒店～', '2023-09-09', 5, '[''整体满意度'', ''前台服务'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233l12000c3iyezfF0A1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230e12000c3j09kaAAE0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232712000c3izrfw562D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '推荐推荐，还是很好的，赞????，比较适合商旅客人入住的酒店，短暂的体验岭南文化', '推荐推荐，还是很好的，赞????，比较适合商旅客人入住的酒店，短暂的体验岭南文化，酒店设计的文化植入点恰到好处', '2023-02-21', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236e12000ap4kxxn03DE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230v12000ap4p0ki981D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232c12000ap4m4vrCCFF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231s12000ap4mnqy26EF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237012000ap4hnwo0D76_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236012000ap4ldhq711A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236n12000ap4ojln55D1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230r12000ap4idq8E96C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '来过几次了，这个价钱有个套房就真的很值，而且前台小姐姐超有礼貌。不过停车不太方便', '来过几次了，这个价钱有个套房就真的很值，而且前台小姐姐超有礼貌。不过停车不太方便，没有独立化妆台和全身镜，可以改进', '2023-02-12', 5, '[''性价比'', ''前台服务'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234i12000anqik7tD5BC_R_150_150_R5_Q70_D.jpg\", \"https://di