-14', 3, '[''卫生状况'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230x12000ao5kqvlF873_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236x12000ao5k6of022E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次带家人来广州旅游，选广州花园酒店真选对了，一进门，宽敞明亮的大堂就让人心情舒', '这次带家人来广州旅游，选广州花园酒店真选对了，一进门，宽敞明亮的大堂就让人心情舒畅，办理入住的速度很快，工作人员还贴心介绍各项服务。客房的设施设备相当高端，灯光能随心调节，洗浴用品也是，用着很舒服。
退房回到家，我意外接到关系专员Lavinia吴灵伶的电话。她说话特别温柔，仔细问我住得好不好，有没有需要改进的地方，言语里都是真诚和关切。这次入住体验超棒，下次来这边，肯定还选这儿！', '2025-03-24', 5, '[''整体满意度'', ''前台服务'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234h12000jakmy50E563_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235u12000jajrcvh3E32_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235512000jakkwofD0D6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230i12000jak9860FC66_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌酒店，白金五星级，这价格性价比还算可以，卫生不错，市中心位置非常好，门口就有', '老牌酒店，白金五星级，这价格性价比还算可以，卫生不错，市中心位置非常好，门口就有地铁、的士，去那里都方便，周边有商场有吃的，入住前台Joe服务热情，还给升级了粤韵房，这很惊喜。', '2023-08-06', 5, '[''性价比'', ''交通便利性'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0231g12000bucyhtw0523_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '让客人在大厅等侯三个小时，服务太差劲了！', '让客人在大厅等侯三个小时，服务太差劲了！', '2023-01-25', 1, '[''前台服务'', ''退房/入住效率'']', '["[ \"https://dimg04.c-ctrip.com/images/0231z12000ai97dcxCBBC_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', 'yomi服务态度好！酒店布置年味十足！', 'yomi服务态度好！酒店布置年味十足！', '2023-01-25', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232012000ai6jv50201B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '很棒的入住体验，下次到广州会再次入住', '很棒的入住体验，下次到广州会再次入住', '2023-01-28', 4, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236a12000aj2zxfiFDE0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233c12000aj2zl7fE49B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '第二次住，太棒了，有花园有博物馆，有底蕴历史的酒店', '第二次住，太棒了，有花园有博物馆，有底蕴历史的酒店', '2023-01-10', 5, '[''周边配套'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0203a12000aez8tnv81B1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0204n12000aez5z90AB0F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0205212000aezalyy48AB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境：??很好特别好', '环境：??很好特别好', '2023-02-15', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231a12000aoa3ex47E09_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233k12000aoa2hw42249_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234f12000aoa4zxr5C2A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌酒店，住的很满意！', '老牌酒店，住的很满意！', '2023-02-12', 4, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232g120008von8nqCB6E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230612000anlkeosBB92_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '设施齐全', '设施齐全
