0dkxlvu365C7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境：特别棒，进门就是看到两幅精致醒目的雕刻画，高端大气，喜欢瀑布餐厅和旋转餐厅', '环境：特别棒，进门就是看到两幅精致醒目的雕刻画，高端大气，喜欢瀑布餐厅和旋转餐厅。

服务：五星级+，前台小姐姐贴心帮我和妈妈帮忙安排到顶楼食早餐，预约参观了酒店，还送了月饼，特别棒的服务体验，谢谢Bella小姐姐。

设施：房间有咖啡机和红酒等，很方便。', '2023-10-07', 5, '[''前台服务'', ''餐饮设施'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230112000cche3yk6963_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234g12000cch947s5657_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232v12000cchbi6v5409_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234n12000cchbi6y509D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231f12000cche6jz7B6A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232b12000cchbgxcE26E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232t12000cchcl8dF393_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235012000cchcu0gD44B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233x12000cchdimg73F0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境不错，房间略旧，出行很方便', '环境不错，房间略旧，出行很方便', '2023-01-24', 5, '[''交通便利性'', ''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233p12000ai21a4hF7AF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232o12000ai1zhylA38B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237412000ai1zcy6A5E1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236212000ai1zd4oD280_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店设施很新，环境卫生完全符合我洁癖老妈要求。', '酒店设施很新，环境卫生完全符合我洁癖老妈要求。
酒店后面藏了一个需要刷房卡才能进的花园，小桥流水，瀑布高悬，别有洞天。在这个寸土寸金的地方可以说很惊喜了。
尤其要感谢前台小哥Joe，非常耐心地听我们的要求，给了很满意的房间，让我们有了两天绝佳的旅行体验。', '2023-02-05', 5, '[''整体满意度'', ''前台服务'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0201x12000alnurfpEFC1_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0232k12000almo4og4EB5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234z12000alnumeeBEB1_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务：服务特别好！！！前台Mancy还帮助我们免费升级了房间！！！！', '服务：服务特别好！！！前台Mancy还帮助我们免费升级了房间！！！！

